// Test script to verify Shopify Files API upload functionality
import axios from 'axios';
import FormData from 'form-data';
import fs from 'fs';
import path from 'path';

async function testShopifyUpload() {
  try {
    // Create a simple test image buffer (1x1 PNG)
    const testImageData = Buffer.from([
      0x89, 0x50, 0x4E, 0x47, 0x0D, 0x0A, 0x1A, 0x0A, 0x00, 0x00, 0x00, 0x0D,
      0x49, 0x48, 0x44, 0x52, 0x00, 0x00, 0x00, 0x01, 0x00, 0x00, 0x00, 0x01,
      0x01, 0x00, 0x00, 0x00, 0x00, 0x37, 0x6E, 0xF9, 0x24, 0x00, 0x00, 0x00,
      0x0A, 0x49, 0x44, 0x41, 0x54, 0x78, 0x9C, 0x63, 0x00, 0x01, 0x00, 0x00,
      0x05, 0x00, 0x01, 0x0D, 0x0A, 0x2D, 0xDB, 0x00, 0x00, 0x00, 0x00, 0x49,
      0x45, 0x4E, 0x44, 0xAE, 0x42, 0x60, 0x82
    ]);

    // Save test image to temp file
    const testImagePath = '/tmp/test_upload.png';
    fs.writeFileSync(testImagePath, testImageData);

    console.log('Created test image at:', testImagePath);

    // Create form data
    const formData = new FormData();
    formData.append('image', fs.createReadStream(testImagePath), {
      filename: 'test_upload.png',
      contentType: 'image/png'
    });

    console.log('Testing Shopify Files API upload...');

    // Make upload request
    const response = await axios.post('http://localhost:5000/api/upload-image', formData, {
      headers: {
        ...formData.getHeaders(),
        'X-Store-ID': '1'
      },
      timeout: 30000
    });

    console.log('Upload response status:', response.status);
    console.log('Upload response data:', JSON.stringify(response.data, null, 2));

    // Check if we got a valid Shopify URL
    if (response.data.success && response.data.url) {
      console.log('✅ Upload successful!');
      console.log('Image URL:', response.data.url);
      console.log('Source:', response.data.source);

      if (response.data.url.includes('shopify.com')) {
        console.log('✅ URL is a valid Shopify CDN URL');
      } else {
        console.log('⚠️ URL is not from Shopify CDN, using fallback');
      }
    } else {
      console.log('❌ Upload failed');
    }

    // Clean up
    fs.unlinkSync(testImagePath);

  } catch (error) {
    console.error('Test failed:', error.message);
    if (error.response) {
      console.error('Response status:', error.response.status);
      console.error('Response data:', JSON.stringify(error.response.data, null, 2));
    }
  }
}

testShopifyUpload();

