import OpenAI from "openai";

// Initialize the OpenAI client with API key from environment
const openai = new OpenAI({ apiKey: process.env.OPENAI_API_KEY });

/**
 * Generate image search term suggestions specifically tailored to products
 * @param productDetails Object containing product information
 * @param count Number of suggestions to generate
 * @returns Array of image search terms
 */
export async function generateProductImageSuggestions(
  productDetails: {
    title: string;
    description?: string;
    category?: string;
    tags?: string[];
    type?: string;
  },
  count: number = 5
): Promise<string[]> {
  try {
    console.log(`Generating product-specific image search terms for: "${productDetails.title}"`);

    // Extract product information to help guide suggestions
    const productTitle = productDetails.title || '';
    const productDescription = productDetails.description || '';
    const productCategory = productDetails.category || '';
    const productTags = productDetails.tags || [];
    const productType = productDetails.type || '';

    // Construct a detailed system prompt that limits to product-relevant suggestions
    const systemPrompt = `You are a product photography expert specializing in e-commerce. 
Your task is to generate ${count} specific, descriptive search terms for finding product photos
that would be perfect to include in a blog post about ${productTitle}.

Focus STRICTLY on terms that would find images showing:
1. The product itself or very similar products
2. The product in use by customers in realistic scenarios
3. Close-ups or detailed views highlighting product features
4. The product in appropriate settings or environments

DO NOT suggest terms for:
- Generic lifestyle scenes unrelated to the product
- Abstract concepts or emotions not directly tied to the product
- Competing products or alternatives
- Any imagery that wouldn't directly feature this specific type of product

The terms should be highly specific and focused on ${productTitle} and its use cases.
Respond ONLY with a JSON array containing your suggestions.`;

    // the newest OpenAI model is "gpt-4o" which was released May 13, 2024. do not change this unless explicitly requested by the user
    const response = await openai.chat.completions.create({
      model: "gpt-4o",
      messages: [
        { 
          role: "system", 
          content: systemPrompt
        },
        { 
          role: "user", 
          content: `
Product Title: ${productTitle}
${productDescription ? `Description: ${productDescription}` : ''}
${productCategory ? `Category: ${productCategory}` : ''}
${productTags.length > 0 ? `Tags: ${productTags.join(', ')}` : ''}
${productType ? `Type: ${productType}` : ''}

Generate ${count} specific image search terms for high-quality product photos that would work well in a blog post about this product.` 
        }
      ],
      temperature: 0.7,
      response_format: { type: "json_object" }
    });

    const content = response.choices[0].message.content;

    if (!content) {
      throw new Error("OpenAI returned an empty response");
    }

    try {
      // Parse the JSON response
      const parsedResponse = JSON.parse(content);

      // Extract suggestions from response - check common property names
      let suggestions: string[] = [];

      if (Array.isArray(parsedResponse.suggestions)) {
        suggestions = parsedResponse.suggestions;
      } else if (Array.isArray(parsedResponse.terms)) {
        suggestions = parsedResponse.terms;
      } else if (Array.isArray(parsedResponse.searchTerms)) {
        suggestions = parsedResponse.searchTerms;
      } else if (Array.isArray(parsedResponse.results)) {
        suggestions = parsedResponse.results;
      } else if (Array.isArray(parsedResponse)) {
        suggestions = parsedResponse;
      } else {
        // If no array found, look for any string array property
        const firstArrayProperty = Object.values(parsedResponse).find(value => 
          Array.isArray(value) && value.length > 0 && typeof value[0] === 'string'
        );

        if (firstArrayProperty) {
          suggestions = firstArrayProperty as string[];
        }
      }

      // Return a fallback if no valid suggestions found
      if (!suggestions || suggestions.length === 0) {
        return [
          `${productTitle} product photo`,
          `${productTitle} in use`,
          `${productTitle} lifestyle`,
          `${productTitle} detailed view`,
          `${productTitle} features`
        ]; 
      }

      // Return suggestions, ensuring we have at most the requested count
      return suggestions.slice(0, count);

    } catch (parseError) {
      console.error("Error parsing image suggestions:", parseError);
      console.log("Raw response:", content);

      // Return fallback suggestions based on product title if parsing fails
      return [
        `${productTitle} product photo`,
        `${productTitle} in use`,
        `${productTitle} lifestyle`,
        `${productTitle} detailed view`,
        `${productTitle} features`
      ];
    }
  } catch (error: any) {
    console.error("OpenAI API error:", error);

    // Fallback suggestions if the API call fails
    return [
      `${productDetails.title} product photo`,
      `${productDetails.title} in use`,
      `${productDetails.title} lifestyle`,
      `${productDetails.title} detailed view`,
      `${productDetails.title} features`
    ];
  }
}

/**
 * Test the OpenAI connection
 */
export async function testOpenAIConnection(): Promise<{ success: boolean; message: string }> {
  try {
    // Make a simple API call to test the connection
    const response = await openai.chat.completions.create({
      model: "gpt-4o",
      messages: [
        { role: "user", content: "Hello, is the connection working? Respond with just yes or no." }
      ],
      max_tokens: 5
    });

    return {
      success: true,
      message: "OpenAI connection successful"
    };
  } catch (error: any) {
    return {
      success: false,
      message: `OpenAI connection failed: ${error.message}`
    };
  }
}

server/services/openai.ts.content:
import OpenAI from "openai";

// Initialize the OpenAI client with API key from environment
const openai = new OpenAI({ apiKey: process.env.OPENAI_API_KEY });

// Define the structure of blog content
export interface BlogContent {
  title: string;
  content: string;
  tags?: string[];
}

/**
 * Generate blog content with a custom prompt
 * @param topic The topic of the blog post
 * @param customPrompt Optional custom prompt template
 * @returns Generated blog content with title and body
 */
export async function generateBlogContent(
  topic: string,
  customPrompt?: string
): Promise<BlogContent> {
  console.log(`Generating blog content for topic: "${topic}" ${customPrompt ? "with custom prompt" : ""}`);

  try {
    // Log the OpenAI key status (not the actual key)
    const apiKeyStatus = process.env.OPENAI_API_KEY ? 
      `API key present (starts with: ${process.env.OPENAI_API_KEY.substring(0, 3)}...)` : 
      "API key missing";
    console.log(`OpenAI API status: ${apiKeyStatus}`);

    // Create a system prompt based on whether a custom prompt was provided
    let systemPrompt = "";

    if (customPrompt) {
      // Replace [TOPIC] placeholder with the actual topic in the custom prompt
      systemPrompt = customPrompt.replace(/\[TOPIC\]/g, topic);

      // Add default instructions if they're not in the custom prompt
      if (!systemPrompt.includes("JSON")) {
        systemPrompt += "\n\nRespond with JSON that includes 'title', 'content', and 'tags' fields.";
      }
    } else {
      // Default system prompt
      systemPrompt = `You are a professional blog writer creating a high-quality blog post about "${topic}".

Write a well-structured blog post that is informative, engaging, and optimized for SEO.
Include a compelling title, an introduction that hooks the reader, several subheadings with detailed content, and a conclusion.
Make the content approximately 500-800 words, with proper formatting including paragraphs and subheadings.

Respond with JSON that includes the following fields:
- title: A catchy, SEO-friendly title for the blog post
- content: The full blog post content with proper formatting (HTML is acceptable)
- tags: An array of 3-5 relevant tags/keywords for this content`;
    }

    console.log("Preparing to call OpenAI API with prompt...");

    // Call OpenAI API to generate the content
    // the newest OpenAI model is "gpt-4o" which was released May 13, 2024. do not change this unless explicitly requested by the user
    console.log("Calling OpenAI Chat Completions API...");

    let userPrompt = "";
    if (customPrompt) {
      // If we have a custom prompt, use a simple user message to avoid conflicting instructions
      userPrompt = `Generate content for "${topic}" using the instructions provided.`;
      console.log("Using custom prompt in system message with simplified user message");
    } else {
      // With the default system prompt, use a more specific user message
      userPrompt = `Write a blog post about "${topic}"`;
    }

    const response = await openai.chat.completions.create({
      model: "gpt-4o",
      messages: [
        { role: "system", content: systemPrompt },
        { role: "user", content: userPrompt }
      ],
      temperature: 0.7,
      response_format: { type: "json_object" }
    });

    console.log("Received response from OpenAI API");

    // Parse the response
    const generatedText = response.choices[0].message.content;

    if (!generatedText) {
      throw new Error("OpenAI returned empty content");
    }

    try {
      // Parse the JSON response
      const blogContent: BlogContent = JSON.parse(generatedText);

      // Validate the required fields
      if (!blogContent.title || !blogContent.content) {
        throw new Error("Generated content missing required fields");
      }

      // Ensure tags is always an array
      if (!blogContent.tags) {
        blogContent.tags = generateDefaultTags(topic);
      }

      return blogContent;
    } catch (parseError) {
      console.error("Error parsing OpenAI response:", parseError);
      console.log("Raw response:", generatedText);

      // Handle the case where the response is not valid JSON
      // Create a fallback structure with the raw text
      return {
        title: `Blog Post about ${topic}`,
        content: generatedText,
        tags: generateDefaultTags(topic)
      };
    }
  } catch (error: any) {
    console.error("OpenAI API error:", error);

    // Rethrow with a more specific error message
    throw new Error(`Failed to generate content: ${error.message}`);
  }
}

/**
 * Bulk generate blog content for multiple topics
 * @param topics Array of topics to generate content for
 * @param customPrompt Optional custom prompt template
 * @returns Array of generated blog content
 */
export async function bulkGenerateBlogContent(
  topics: string[],
  customPrompt?: string
): Promise<BlogContent[]> {
  console.log(`Bulk generating content for ${topics.length} topics ${customPrompt ? "with custom prompt" : ""}`);

  // Generate content for each topic sequentially
  const results: BlogContent[] = [];

  for (const topic of topics) {
    try {
      const content = await generateBlogContent(topic, customPrompt);
      results.push(content);

      // Add a short delay between API calls to avoid rate limiting
      await new Promise(resolve => setTimeout(resolve, 1000));
    } catch (error) {
      console.error(`Error generating content for topic "${topic}":`, error);
      // Continue with the next topic instead of failing the entire batch
    }
  }

  return results;
}

/**
 * Generate blog topic suggestions based on a niche or industry
 */
export async function generateTopicSuggestions(
  niche: string,
  count: number = 10
): Promise<string[]> {
  try {
    // the newest OpenAI model is "gpt-4o" which was released May 13, 2024. do not change this unless explicitly requested by the user
    const response = await openai.chat.completions.create({
      model: "gpt-4o",
      messages: [
        { 
          role: "system", 
          content: `You are a blog content strategist. Generate ${count} blog topic ideas for the ${niche} niche. 
          Focus on topics that will drive traffic and engage readers. 
          Create topics that would be helpful for the target audience.

          Respond with a JSON array of strings, with each string being a topic idea.`
        },
        { 
          role: "user", 
          content: `Generate ${count} blog topic ideas for the ${niche} niche.` 
        }
      ],
      temperature: 0.8,
      response_format: { type: "json_object" }
    });

    const content = response.choices[0].message.content;

    if (!content) {
      throw new Error("OpenAI returned an empty response");
    }

    try {
      // Parse the JSON response
      const parsedResponse = JSON.parse(content);

      // Check if the response has a topics array
      if (Array.isArray(parsedResponse.topics)) {
        return parsedResponse.topics;
      }

      // If the response is an array directly
      if (Array.isArray(parsedResponse)) {
        return parsedResponse;
      }

      // If there's no proper array, extract any string array property
      const firstArrayProperty = Object.values(parsedResponse).find(value => 
        Array.isArray(value) && value.length > 0 && typeof value[0] === 'string'
      );

      if (firstArrayProperty) {
        return firstArrayProperty as string[];
      }

      throw new Error("Could not find topics array in response");
    } catch (parseError) {
      console.error("Error parsing topic suggestions:", parseError);
      throw new Error("Failed to parse topic suggestions");
    }
  } catch (error: any) {
    console.error("OpenAI API error:", error);
    throw new Error(`Failed to generate topic suggestions: ${error.message}`);
  }
}

/**
 * Generate default tags based on a topic
 * @param topic The blog post topic
 * @returns Array of default tags
 */
function generateDefaultTags(topic: string): string[] {
  // Convert the topic to tags
  const mainTag = topic.toLowerCase()
    .replace(/[^\w\s]/g, '') // Remove special characters
    .trim();

  // Add some generic tags
  return [mainTag, 'blog', 'article', 'guide'];
}

server/services/pexels.ts.content:
// Pexels API Integration Service
import axios from 'axios';

// Interface for Pexels image data
export interface PexelsImage {
  id: string;
  width: number;
  height: number;
  url: string;
  src: {
    original: string;
    large: string;
    medium: string;
    small: string;
    thumbnail: string;
  };
  photographer: string;
  photographer_url: string;
  alt: string;
  avg_color?: string;
}

export class PexelsService {
  private apiKey: string;
  private apiUrl: string;

  constructor() {
    this.apiKey = process.env.PEXELS_API_KEY || 'WV6MTEoHntfeFldjjKUHn94CtcwTAyPYxlFHS7oUDF7r5gtIPiyXA0pr';
    this.apiUrl = 'https://api.pexels.com/v1';
  }

  /**
   * Check if API key is set
   */
  public hasValidApiKey(): boolean {
    return !!this.apiKey && this.apiKey.length > 0;
  }

  /**
   * Search for images using Pexels API
   * @param query Search query term
   * @param count Number of images to return
   * @returns Array of image data
   */
  public async searchImages(query: string, count: number = 10): Promise<PexelsImage[]> {
    try {
      if (!this.hasValidApiKey()) {
        throw new Error('No Pexels API key found');
      }

      console.log(`Searching Pexels for: "${query}"`);

      // Make request to Pexels API
      const response = await axios.get(`${this.apiUrl}/search`, {
        headers: {
          'Authorization': this.apiKey
        },
        params: {
          query: query,
          per_page: count,
          orientation: 'landscape' // Prefer landscape images for blogs
        }
      });

      console.log(`Pexels search returned ${response.data.photos.length} results`);

      // Map response to our PexelsImage interface
      const images = response.data.photos.map((photo: any) => ({
        id: photo.id.toString(),
        width: photo.width,
        height: photo.height,
        url: photo.url,
        src: {
          original: photo.src.original,
          large: photo.src.large,
          medium: photo.src.medium,
          small: photo.src.small,
          thumbnail: photo.src.tiny
        },
        photographer: photo.photographer,
        photographer_url: photo.photographer_url,
        alt: photo.alt || query
      }));

      return images;
    } catch (error: any) {
      console.error('Error searching Pexels API:', error.message);
      throw new Error(`Failed to search Pexels: ${error.message}`);
    }
  }

  /**
   * Get curated images from Pexels
   * @param count Number of images to return
   * @returns Array of image data
   */
  public async getCuratedImages(count: number = 5): Promise<PexelsImage[]> {
    try {
      if (!this.hasValidApiKey()) {
        throw new Error('No Pexels API key found');
      }

      console.log(`Getting ${count} curated images from Pexels`);

      // Make request to Pexels API
      const response = await axios.get(`${this.apiUrl}/curated`, {
        headers: {
          'Authorization': this.apiKey
        },
        params: {
          per_page: count
        }
      });

      console.log(`Pexels curated returned ${response.data.photos.length} results`);

      // Map response to our PexelsImage interface
      const images = response.data.photos.map((photo: any) => ({
        id: photo.id.toString(),
        width: photo.width,
        height: photo.height,
        url: photo.url,
        src: {
          original: photo.src.original,
          large: photo.src.large,
          medium: photo.src.medium,
          small: photo.src.small,
          thumbnail: photo.src.tiny
        },
        photographer: photo.photographer,
        photographer_url: photo.photographer_url,
        alt: photo.alt || 'Curated image from Pexels'
      }));

      return images;
    } catch (error: any) {
      console.error('Error getting curated images from Pexels API:', error.message);
      throw new Error(`Failed to get curated images from Pexels: ${error.message}`);
    }
  }

  /**
   * Generate fallback images when API fails
   * @param count Number of fallback images
   * @returns Array of fallback image data
   */
  private generateFallbackImages(count: number = 10): PexelsImage[] {
    console.log(`Generating ${count} fallback images`);

    // Placeholder image URLs with more variety for up to 10 images
    const placeholderColors = ['555555', '666666', '777777', '888888', '999999', 'aaaaaa', 'bbbbbb', 'cccccc', 'dddddd', 'eeeeee'];

    // Generate array of fallback images
    return Array.from({ length: count }).map((_, index) => ({
      id: `fallback-${index}`,
      width: 800,
      height: 600,
      url: `https://placeholder.com/800x600/${placeholderColors[index % placeholderColors.length]}`,
      src: {
        original: `https://placeholder.com/800x600/${placeholderColors[index % placeholderColors.length]}`,
        large: `https://placeholder.com/800x600/${placeholderColors[index % placeholderColors.length]}`,
        medium: `https://placeholder.com/600x400/${placeholderColors[index % placeholderColors.length]}`,
        small: `https://placeholder.com/400x300/${placeholderColors[index % placeholderColors.length]}`,
        thumbnail: `https://placeholder.com/200x150/${placeholderColors[index % placeholderColors.length]}`
      },
      photographer: 'Placeholder',
      photographer_url: 'https://placeholder.com',
      alt: 'Placeholder image'
    }));
  }

  /**
   * Get a specific image by its ID
   * @param id The Pexels image ID
   * @returns The image data or null if not found
   */
  public async getImageById(id: string): Promise<PexelsImage | null> {
    try {
      if (!this.hasValidApiKey()) {
        throw new Error('No Pexels API key found');
      }

      console.log(`Fetching Pexels image with ID: ${id}`);

      // Make request to Pexels API
      const response = await axios.get(`${this.apiUrl}/photos/${id}`, {
        headers: {
          'Authorization': this.apiKey
        }
      });

      const photo = response.data;

      // Map response to our PexelsImage interface
      return {
        id: photo.id.toString(),
        width: photo.width,
        height: photo.height,
        url: photo.url,
        src: {
          original: photo.src.original,
          large: photo.src.large,
          medium: photo.src.medium,
          small: photo.src.small,
          thumbnail: photo.src.tiny
        },
        photographer: photo.photographer,
        photographer_url: photo.photographer_url,
        alt: photo.alt || `Pexels image ${id}`
      };
    } catch (error: any) {
      console.error(`Error fetching Pexels image ID ${id}:`, error.message);
      return null;
    }
  }

  /**
   * Get multiple images by their IDs
   * @param ids Array of Pexels image IDs
   * @returns Array of found images (may be less than requested if some IDs are invalid)
   */
  public async getImagesByIds(ids: string[]): Promise<PexelsImage[]> {
    // Remove duplicates using filter instead of Set for better compatibility
    const uniqueIds = ids.filter((id, index) => ids.indexOf(id) === index);
    const images: PexelsImage[] = [];

    console.log(`Fetching ${uniqueIds.length} specific Pexels images by ID`);

    // Fetch each image individually
    for (const id of uniqueIds) {
      try {
        const image = await this.getImageById(id);
        if (image) {
          images.push(image);
        }
      } catch (error) {
        console.error(`Error fetching image ID ${id}:`, error);
        // Continue with the next image
      }
    }

    console.log(`Successfully fetched ${images.length} out of ${uniqueIds.length} requested images`);
    return images;
  }

  /**
   * Safely search for images with fallback
   * @param query Search query term
   * @param count Number of images to return
   * @returns Images and fallback status
   */
  public async safeSearchImages(query: string, count: number = 10): Promise<{ 
    images: PexelsImage[], 
