import Anthropic from '@anthropic-ai/sdk';
import { shopifyApiRequest } from './shopify-api';
import { logger } from '../logger';

// the newest Anthropic model is "claude-3-7-sonnet-20250219" which was released February 24, 2025
const anthropic = new Anthropic({
  apiKey: process.env.ANTHROPIC_API_KEY,
});

/**
 * Interface for product analysis results
 */
export interface ProductAnalysisResult {
  original: {
    title: string;
    description: string;
  };
  analysis: {
    strengths: string[];
    weaknesses: string[];
    seoScore: number;
    readabilityScore: number;
    targetAudience: string[];
    emotionalAppeal: number;
  };
  suggestions: {
    improvedTitle: string;
    improvedDescription: string;
    keywords: string[];
    callToAction: string;
  };
}

/**
 * Analyze a product using Claude AI
 * @param storeUrl The Shopify store URL
 * @param accessToken The Shopify access token
 * @param productId The product ID to analyze
 */
export async function analyzeProduct(
  storeUrl: string,
  accessToken: string,
  productId: string
): Promise<ProductAnalysisResult> {
  try {
    // Fetch the product details from Shopify
    const productResponse = await shopifyApiRequest(
      storeUrl,
      accessToken,
      `GET`,
      `/products/${productId}.json`
    );

    if (!productResponse.success || !productResponse.data.product) {
      throw new Error('Failed to fetch product details');
    }

    const product = productResponse.data.product;
    const title = product.title;
    const description = product.body_html?.replace(/<[^>]*>/g, ' ').trim() || '';
    const price = product.variants[0]?.price || 'N/A';
    const tags = product.tags || '';
    const productType = product.product_type || '';
    const images = product.images?.length || 0;

    // Format product data for analysis
    const productInfo = `
      Title: ${title}
      Description: ${description}
      Price: ${price}
      Product Type: ${productType}
      Tags: ${tags}
      Number of Images: ${images}
    `;

    // Create the prompt for Claude
    const response = await anthropic.messages.create({
      model: 'claude-3-7-sonnet-20250219',
      max_tokens: 1500,
      system: `You are an expert e-commerce and SEO consultant specializing in Shopify product listings. 
      Analyze the following product details and provide constructive feedback to improve sales and SEO.
      Format your response as valid JSON with the following structure:
      {
        "analysis": {
          "strengths": [array of string strengths],
          "weaknesses": [array of string weaknesses],
          "seoScore": number from 1-10,
          "readabilityScore": number from 1-10,
          "targetAudience": [array of potential customer types],
          "emotionalAppeal": number from 1-10
        },
        "suggestions": {
          "improvedTitle": "string with SEO-optimized title",
          "improvedDescription": "string with enhanced product description (HTML allowed)",
          "keywords": [array of recommended keywords],
          "callToAction": "string with effective call to action"
        }
      }`,
      messages: [
        {
          role: 'user', 
          content: `Please analyze this Shopify product listing and provide detailed feedback with specific improvements:\n\n${productInfo}`
        }
      ],
    });

    // Parse the JSON response
    const jsonResponseText = response.content[0].text;
    const jsonResponse = JSON.parse(jsonResponseText);

    // Return the analysis result
    return {
      original: {
        title,
        description,
      },
      analysis: jsonResponse.analysis,
      suggestions: jsonResponse.suggestions,
    };
  } catch (error) {
    logger.error('Error analyzing product:', error);
    throw new Error(`Failed to analyze product: ${error.message}`);
  }
}

/**
 * Apply suggested improvements to a product
 * @param storeUrl The Shopify store URL
 * @param accessToken The Shopify access token
 * @param productId The product ID to update
 * @param improvements The improvements to apply
 */
export async function applyProductImprovements(
  storeUrl: string,
  accessToken: string,
  productId: string,
  improvements: {
    title?: string;
    description?: string;
    metafields?: {
      key: string;
      value: string;
      type: string;
      namespace: string;
    }[];
  }
): Promise<{ success: boolean; message: string }> {
  try {
    // Create the product update payload
    const updatePayload: any = {
      product: {
        id: productId,
      },
    };

    if (improvements.title) {
      updatePayload.product.title = improvements.title;
    }

    if (improvements.description) {
      updatePayload.product.body_html = improvements.description;
    }

    // Update the product in Shopify
    const updateResponse = await shopifyApiRequest(
      storeUrl,
      accessToken,
      `PUT`,
      `/products/${productId}.json`,
      updatePayload
    );

    if (!updateResponse.success) {
      throw new Error('Failed to update product');
    }

    // If there are metafields to update
    if (improvements.metafields && improvements.metafields.length > 0) {
      for (const metafield of improvements.metafields) {
        const metafieldPayload = {
          metafield: {
            namespace: metafield.namespace,
            key: metafield.key,
            value: metafield.value,
            type: metafield.type,
          },
        };

        await shopifyApiRequest(
          storeUrl,
          accessToken,
          `POST`,
          `/products/${productId}/metafields.json`,
          metafieldPayload
        );
      }
    }

    return {
      success: true,
      message: 'Product improvements applied successfully',
    };
  } catch (error) {
    logger.error('Error applying product improvements:', error);
    return {
      success: false,
      message: `Failed to apply improvements: ${error.message}`,
    };
  }
}

server/services/shopify-scheduling-fix.t.content:
/**
 * Direct implementation of Shopify scheduling based on latest Admin API docs
 * https://shopify.dev/docs/api/admin-rest/2023-07/resources/article
 * 
 * The key insight is that we need to use Shopify's status field correctly:
 * - active: The article is active (published)
 * - draft: The article is a draft and not published
 * 
 * For scheduling, we need:
 * 1. status: 'draft'
 * 2. published_at: future date
 */

// Define the ShopifyStore type inline for our implementation
interface ShopifyStore {
  id: number;
  shopName: string;
  accessToken: string;
  scope: string;
  isConnected: boolean;
  defaultBlogId?: string;
}
import axios, { AxiosInstance } from "axios";

/**
 * Creates a scheduled article in Shopify using 2025-07 API version explicitly
 * which has better handling of scheduled content
 * @param store Shopify store details
 * @param blogId The blog ID to create the article in
 * @param title Article title
 * @param content Article HTML content
 * @param scheduledDate Future date when article should be published
 * @param tags Optional tags for the article
 * @param featuredImage Optional featured image URL
 */
export async function createScheduledArticle(
  store: ShopifyStore,
  blogId: string,
  title: string,
  content: string,
  scheduledDate: Date,
  tags: string = "",
  featuredImage?: string
): Promise<any> {
  try {
    // Create a specific client for 2025-07 API version (latest with better scheduling)
    const client = axios.create({
      baseURL: `https://${store.shopName}/admin/api/2025-07`,
      headers: {
        'Content-Type': 'application/json',
        'X-Shopify-Access-Token': store.accessToken
      }
    });

    // Ensure date is in future
    const now = new Date();
    if (scheduledDate <= now) {
      // Set to tomorrow at 9 AM
      const tomorrow = new Date();
      tomorrow.setDate(tomorrow.getDate() + 1);
      tomorrow.setHours(9, 0, 0, 0); // 9 AM tomorrow
      scheduledDate = tomorrow;
      console.log(`Adjusted scheduled date to tomorrow 9 AM: ${scheduledDate.toISOString()}`);
    }

    // Make sure date is at least 2 hours in the future to avoid scheduling issues
    const twoHoursFromNow = new Date(now.getTime() + (2 * 60 * 60 * 1000));
    if (scheduledDate < twoHoursFromNow) {
      scheduledDate = twoHoursFromNow;
      console.log(`Adjusted scheduled date to be at least 2 hours in future: ${scheduledDate.toISOString()}`);
    }

    // Build the article payload with explicit status=scheduled
    const article: any = {
      title: title,
      author: store.shopName,
      body_html: content,
      tags: tags,
      // Using explicit published=false and published_at in the future date
      // This is the most reliable way to schedule in recent Shopify API versions
      published: false,
      published_at: scheduledDate.toISOString()
    };

    if (featuredImage) {
      article.image = { src: featuredImage };
    }

    console.log(`Creating scheduled article with explicit API version 2025-07 (better scheduling):`, {
      title,
      published: article.published,
      published_at: article.published_at
    });

    // Make the API request
    const response = await client.post(`/blogs/${blogId}/articles.json`, { article });

    console.log(`Article created with schedule:`, {
      id: response.data.article.id,
      title: response.data.article.title,
      published: response.data.article.published,
      published_at: response.data.article.published_at
    });

    // Verify the publishing date matches what we expect
    if (response.data.article.published_at) {
      const responseDate = new Date(response.data.article.published_at);
      const sentDate = new Date(article.published_at);
      const timeDiffMinutes = Math.abs(responseDate.getTime() - sentDate.getTime()) / (60 * 1000);

      console.log(`Schedule verification: 
        - Sent date: ${sentDate.toISOString()}
        - Response date: ${responseDate.toISOString()}
        - Difference: ${Math.round(timeDiffMinutes)} minutes`);

      // If published immediately instead of scheduled, try to update it to scheduled
      if (response.data.article.published === true) {
        console.log("⚠️ WARNING: Article was published immediately, attempting to fix...");

        try {
          // Make a second request to update the article to be scheduled
          const updateResponse = await client.put(
            `/blogs/${blogId}/articles/${response.data.article.id}.json`, 
            { 
              article: {
                id: response.data.article.id,
                published: false,
                published_at: scheduledDate.toISOString()
              } 
            }
          );

          console.log("Article scheduling fix response:", {
            id: updateResponse.data.article.id,
            published: updateResponse.data.article.published,
            published_at: updateResponse.data.article.published_at
          });

          return updateResponse.data.article;
        } catch (updateError) {
          console.error("Failed to update article scheduling:", updateError);
        }
      }
    }

    return response.data.article;
  } catch (error: any) {
    console.error(`Error creating scheduled article:`, error);
    if (error.response) {
      console.error(`Shopify API error:`, {
        status: error.response.status,
        data: error.response.data
      });
    }
    throw new Error(`Failed to create scheduled article: ${error?.message || 'Unknown error'}`);
  }
}

/**
 * Creates a scheduled page in Shopify using 2025-07 API version explicitly
 * which has better handling of scheduled content
 * @param store Shopify store details 
 * @param title Page title
 * @param content Page HTML content
 * @param scheduledDate Future date when page should be published
 */
