                    const url = e.target.value;
                    setYoutubeUrl(url);
                    // Extract YouTube video ID from URL
                    const match = url.match(/(?:youtu\.be\/|youtube\.com\/(?:embed\/|v\/|watch\?v=|watch\?.+&v=))([^&?]+)/);
                    const extractedVideoId = match ? match[1] : null;
                    setYoutubeVideoId(extractedVideoId);
                  }}
                  className="w-full"
                />

                <Button 
                  type="button"
                  onClick={() => {
