import * as React from "react";
import { X, Check, Image, ChevronsUpDown, Search } from "lucide-react";
import { Badge } from "@/components/ui/badge";
import { 
  Popover,
  PopoverContent,
  PopoverTrigger
} from "@/components/ui/popover";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { ScrollArea } from "@/components/ui/scroll-area";
import { cn } from "@/lib/utils";

interface Product {
  id: string;
  title: string;
  images?: Array<{
    id: number;
    src: string;
    alt?: string;
  }>;
}

interface ProductSelectOption {
  product: Product;
  value: string;
}

interface ProductMultiSelectProps {
  options: ProductSelectOption[];
  selected: string[];
  onChange: (selected: string[]) => void;
  placeholder?: string;
  className?: string;
  disabled?: boolean;
}

export function ProductMultiSelect({
  options,
  selected = [],
  onChange,
  placeholder = "Select products...",
  className,
  disabled = false,
}: ProductMultiSelectProps) {
  // State for the search filter
  const [searchQuery, setSearchQuery] = React.useState("");
  const [open, setOpen] = React.useState(false);

  // Ensure selected is always an array, even if it's undefined
  const selectedValues = Array.isArray(selected) ? selected : [];

  // Filter options based on search query
  const filteredOptions = options.filter(option => 
    option.product.title.toLowerCase().includes(searchQuery.toLowerCase())
  );

  // Remove an item from selection
  const handleRemove = (valueToRemove: string) => {
    onChange(selectedValues.filter(value => value !== valueToRemove));
  };

  // Add an item to selection
  const handleSelect = (newValue: string) => {
    if (!selectedValues.includes(newValue)) {
      onChange([...selectedValues, newValue]);
    } else {
      // If already selected, remove it (toggle behavior)
      onChange(selectedValues.filter(value => value !== newValue));
    }
  };

  // Find a product by its ID
  const getProductById = (id: string): Product | undefined => {
    const option = options.find(opt => opt.value === id);
    return option?.product;
  };

  // Get image URL for a product
  const getProductImageUrl = (product: Product | undefined): string => {
    if (!product || !product.images || product.images.length === 0) {
      return "";
    }
    return product.images[0].src;
  };

  // Get a comma-separated list of selected items for the trigger display
  const getSelectedDisplay = (): string => {
    if (selectedValues.length === 0) {
      return placeholder;
    }

    if (selectedValues.length === 1) {
      const product = getProductById(selectedValues[0]);
      return product?.title || "1 product selected";
    }

    return `${selectedValues.length} products selected`;
  };

  return (
    <div className={cn("space-y-2", className)}>
      <Popover open={open} onOpenChange={setOpen}>
        <PopoverTrigger asChild>
          <Button
            variant="outline"
            role="combobox"
            aria-expanded={open}
            disabled={disabled}
            className="w-full justify-between font-normal h-auto py-2"
          >
            {getSelectedDisplay()}
            <ChevronsUpDown className="ml-2 h-4 w-4 shrink-0 opacity-50" />
          </Button>
        </PopoverTrigger>
        <PopoverContent className="w-full p-0" align="start">
          <div className="p-2 border-b">
            <div className="relative">
              <Search className="absolute left-2.5 top-2.5 h-4 w-4 text-muted-foreground" />
              <Input
                placeholder="Search products..."
                className="pl-8"
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
              />
            </div>
          </div>

          <ScrollArea className="h-[300px]">
            <div className="p-2">
              {filteredOptions.length === 0 ? (
                <div className="p-4 text-center text-sm text-muted-foreground">
                  No products found
                </div>
              ) : (
                filteredOptions.map((option) => {
                  const isSelected = selectedValues.includes(option.value);
                  const product = option.product;
                  const imageUrl = getProductImageUrl(product);

                  return (
                    <div
                      key={option.value}
                      className={cn(
                        "flex items-center gap-2 p-2 rounded-md cursor-pointer",
                        isSelected ? "bg-secondary" : "hover:bg-accent"
                      )}
                      onClick={() => handleSelect(option.value)}
                    >
                      {/* Product Image */}
                      <div className="flex-shrink-0 w-10 h-10 rounded-md overflow-hidden bg-secondary border">
                        {imageUrl ? (
                          <img 
                            src={imageUrl} 
                            alt={product.title} 
                            className="w-full h-full object-cover"
                          />
                        ) : (
                          <div className="w-full h-full flex items-center justify-center">
                            <Image className="h-5 w-5 text-muted-foreground" />
                          </div>
                        )}
                      </div>

                      {/* Product Title */}
                      <div className="flex-1 truncate text-sm">
                        {product.title}
                      </div>

                      {/* Selection Indicator */}
                      {isSelected && (
                        <Check className="h-4 w-4 text-primary" />
                      )}
                    </div>
                  );
                })
              )}
            </div>
          </ScrollArea>
        </PopoverContent>
      </Popover>

      {/* Selected Products Pills */}
      {selectedValues.length > 0 && (
        <div className="flex flex-wrap gap-1.5 mt-1.5">
          {selectedValues.map((value) => {
            const product = getProductById(value);
            if (!product) return null;

            return (
              <Badge
                key={value}
                variant="secondary"
                className="py-1 pl-1 pr-1.5 gap-1.5 items-center"
              >
                {/* Tiny product image */}
                <div className="w-5 h-5 rounded overflow-hidden bg-background flex-shrink-0">
                  {getProductImageUrl(product) ? (
                    <img 
                      src={getProductImageUrl(product)} 
                      alt={product.title}
                      className="w-full h-full object-cover" 
                    />
                  ) : (
                    <div className="w-full h-full flex items-center justify-center">
                      <Image className="h-3 w-3 text-muted-foreground" />
                    </div>
                  )}
                </div>

                <span className="truncate max-w-[180px]">{product.title}</span>

                <button
                  className="hover:bg-muted rounded-full p-0.5 focus:outline-none"
                  onClick={(e) => {
                    e.stopPropagation();
                    handleRemove(value);
                  }}
                >
                  <X className="h-3 w-3" />
                </button>
              </Badge>
            );
          })}
        </div>
      )}
    </div>
  );
}

client/src/components/ProjectCreationDia.content:
import React, { useState } from 'react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Textarea } from '@/components/ui/textarea';
import { Label } from '@/components/ui/label';
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog';
import { useToast } from '@/hooks/use-toast';
import { useMutation, useQueryClient } from '@tanstack/react-query';
import { apiRequest } from '@/lib/queryClient';
import { useStore } from '@/contexts/StoreContext';

interface ProjectCreationDialogProps {
  isOpen: boolean;
  onClose: () => void;
  onProjectCreated: (project: any) => void;
}

export function ProjectCreationDialog({ isOpen, onClose, onProjectCreated }: ProjectCreationDialogProps) {
  const [name, setName] = useState('');
  const [description, setDescription] = useState('');
  const { toast } = useToast();
  const queryClient = useQueryClient();
  const { autoDetectedStoreId } = useStore();

  const createProjectMutation = useMutation({
    mutationFn: (data: { name: string; description?: string; projectData: string }) =>
      apiRequest('POST', '/api/projects', data),
    onSuccess: (response) => {
      queryClient.invalidateQueries({ queryKey: ['/api/projects'] });
      onProjectCreated(response.project);
      onClose();
      setName('');
      setDescription('');
      toast({
        title: "Project created successfully",
        description: `"${response.project.name}" has been created.`,
      });
    },
    onError: (error: any) => {
      toast({
        title: "Error creating project",
        description: error.message || "Failed to create project",
        variant: "destructive",
      });
    },
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    if (!name.trim()) {
      toast({
        title: "Project name required",
        description: "Please enter a project name",
        variant: "destructive",
      });
      return;
    }

    // Create with empty project data initially
    createProjectMutation.mutate({
      name: name.trim(),
      description: description.trim() || undefined,
      projectData: JSON.stringify({}), // Empty initial state
    });
  };

  const handleClose = () => {
    setName('');
    setDescription('');
    onClose();
  };

  return (
    <Dialog open={isOpen} onOpenChange={handleClose}>
      <DialogContent className="sm:max-w-md">
        <DialogHeader>
          <DialogTitle>Create New Project</DialogTitle>
          <DialogDescription>
            Create a new project to save your form state and continue working later.
          </DialogDescription>
        </DialogHeader>
        <form onSubmit={handleSubmit} className="space-y-4">
          <div className="space-y-2">
            <Label htmlFor="name">Project Name *</Label>
            <Input
              id="name"
              value={name}
              onChange={(e) => setName(e.target.value)}
              placeholder="Enter project name"
              required
            />
          </div>
          <div className="space-y-2">
            <Label htmlFor="description">Description (optional)</Label>
            <Textarea
              id="description"
              value={description}
              onChange={(e) => setDescription(e.target.value)}
              placeholder="Enter project description"
              rows={3}
            />
          </div>
          <DialogFooter className="flex gap-2">
            <Button type="button" variant="outline" onClick={handleClose}>
              Cancel
            </Button>
            <Button 
              type="submit" 
              disabled={createProjectMutation.isPending || !name.trim()}
            >
              {createProjectMutation.isPending ? "Creating..." : "Create Project"}
            </Button>
          </DialogFooter>
        </form>
      </DialogContent>
    </Dialog>
  );
}

client/src/components/ProjectDialog.tsx.content:
import React, { useState } from "react";
import { 
  Dialog, 
  DialogContent, 
  DialogDescription, 
  DialogFooter, 
  DialogHeader, 
  DialogTitle 
} from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { FolderPlus, Info } from "lucide-react";
import { Tooltip, TooltipContent, TooltipProvider, TooltipTrigger } from "@/components/ui/tooltip";
import { useToast } from "@/hooks/use-toast";

interface ProjectDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  onProjectCreated: (projectName: string) => void;
}

export default function ProjectDialog({
  open,
  onOpenChange,
  onProjectCreated
}: ProjectDialogProps) {
  const [projectName, setProjectName] = useState("");
  const [isSubmitting, setIsSubmitting] = useState(false);
  const { toast } = useToast();

  // Reset form when dialog opens
  React.useEffect(() => {
    if (open) {
      setProjectName("");
    }
  }, [open]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    if (!projectName || projectName.trim().length < 3) {
      toast({
        title: "Project name required",
        description: "Please enter a project name with at least 3 characters",
        variant: "destructive"
      });
      return;
    }

    setIsSubmitting(true);

    // Process the project creation
    setTimeout(() => {
      onProjectCreated(projectName);

      toast({
        title: "Project created successfully",
        description: `"${projectName}" has been created and set as your current project.`
      });

      setIsSubmitting(false);
      onOpenChange(false);
    }, 500);
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-[500px]">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2 text-xl">
            <FolderPlus className="h-5 w-5 text-primary" />
            Create New Project
          </DialogTitle>
          <DialogDescription>
            Start by naming your content generation project.
          </DialogDescription>
        </DialogHeader>

        <form onSubmit={handleSubmit} className="space-y-6 py-4">
