}: ProjectNameDialogProps) {
  const [projectName, setProjectName] = useState("");
  const [isSubmitting, setIsSubmitting] = useState(false);
  const { toast } = useToast();

  // Reset the form when the dialog opens
  React.useEffect(() => {
