import React, { useState } from 'react';
import { Button } from './ui/button';
import { Separator } from './ui/separator';
import { MediaImage } from './MediaSelectionStep';
import ShopifyImageViewer from './ShopifyImageViewer';
import { X, Eye, ArrowUp, Trash2, Plus, Star, ImageIcon } from 'lucide-react';
import { useToast } from '../hooks/use-toast';

interface SelectedImagesPanelProps {
  primaryImage: MediaImage | null;
  secondaryImages: MediaImage[];
  setPrimaryImage: (image: MediaImage | null) => void;
  setSecondaryImages: (images: MediaImage[]) => void;
  onPreviewImage: (image: MediaImage) => void;
}

export function SelectedImagesPanel({
  primaryImage,
  secondaryImages,
  setPrimaryImage,
  setSecondaryImages,
  onPreviewImage
}: SelectedImagesPanelProps) {
  const { toast } = useToast();
  const [isCollapsed, setIsCollapsed] = useState(false);

  // Promote a secondary image to primary
  const promoteToFeatured = (image: MediaImage) => {
    // If there's already a primary image, swap it to secondary
    if (primaryImage) {
      setSecondaryImages([...secondaryImages.filter(img => img.id !== image.id), primaryImage]);
    } else {
      setSecondaryImages(secondaryImages.filter(img => img.id !== image.id));
    }

    setPrimaryImage(image);
    toast({
      title: "Image promoted",
      description: "Image has been set as primary featured image"
    });
  };

  // Count total selected images
  const totalSelectedImages = (primaryImage ? 1 : 0) + secondaryImages.length;

  return (
    <div className="border border-slate-200 rounded-md bg-slate-50 mb-6 overflow-hidden">
      <div 
        className="flex items-center justify-between p-3 cursor-pointer hover:bg-slate-100"
        onClick={() => setIsCollapsed(!isCollapsed)}
      >
        <h3 className="text-lg font-medium flex items-center">
          <Star className={`h-4 w-4 mr-2 ${primaryImage ? 'text-blue-600' : 'text-slate-400'}`} />
          Selected Images ({totalSelectedImages})
        </h3>
        <Button variant="ghost" size="sm" onClick={(e) => {
          e.stopPropagation();
          setIsCollapsed(!isCollapsed);
        }}>
          {isCollapsed ? 'Show' : 'Hide'}
        </Button>
      </div>

      {!isCollapsed && (
        <div className="p-4 pt-0">
          {/* Primary Featured Image */}
          <div className="mb-4">
            <h4 className="text-sm font-medium text-blue-700 flex items-center mb-2">
              <Star className="h-4 w-4 mr-1 text-blue-600" />
              Primary Image {primaryImage ? "" : "(Not Selected)"}
            </h4>

            {primaryImage ? (
              <div className="relative aspect-video w-full max-w-md bg-blue-50 rounded-md overflow-hidden border-2 border-blue-300">
                <ShopifyImageViewer 
                  src={primaryImage.url} 
                  alt={primaryImage.alt || "Primary image"} 
                  className="w-full h-full" 
                  objectFit="cover"
                  selected={true}
                  selectionType="primary"
                />
                <div className="absolute top-2 right-2 flex gap-1">
                  <Button 
                    size="sm"
                    variant="secondary"
                    className="h-8 w-8 p-0 rounded-full bg-white/90 hover:bg-white"
                    onClick={() => onPreviewImage(primaryImage)}
                  >
                    <Eye className="h-4 w-4" />
                  </Button>
                  <Button 
                    size="sm"
                    variant="destructive"
                    className="h-8 w-8 p-0 rounded-full bg-white/90 text-red-600 hover:text-red-700 hover:bg-white"
                    onClick={() => setPrimaryImage(null)}
                  >
                    <X className="h-4 w-4" />
                  </Button>
                </div>
              </div>
            ) : (
              <div className="flex items-center justify-center bg-blue-50 border-2 border-dashed border-blue-200 rounded-md aspect-video w-full max-w-md">
                <div className="text-center p-4">
                  <ImageIcon className="h-10 w-10 mx-auto text-blue-300" />
                  <p className="mt-2 text-sm text-blue-500">No primary image selected</p>
                  <p className="text-xs text-blue-400">Choose an image below and select "Primary"</p>
                </div>
              </div>
            )}
          </div>

          <Separator className="my-4" />

          {/* Secondary Images */}
          <div>
            <h4 className="text-sm font-medium text-green-700 flex items-center mb-2">
              <Plus className="h-4 w-4 mr-1 text-green-600" />
              Secondary Images {secondaryImages.length > 0 ? `(${secondaryImages.length})` : "(Not Selected)"}
            </h4>

            {secondaryImages.length > 0 ? (
              <div>
                <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 gap-2">
                  {secondaryImages.map(image => (
                    <div key={image.id} className="group relative aspect-video rounded-md overflow-hidden border-2 border-green-200">
                      <ShopifyImageViewer 
                        src={image.url} 
                        alt={image.alt || ""} 
                        className="w-full h-full" 
                        objectFit="cover"
                        selected={true}
                        selectionType="secondary"
                      />
                      <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center gap-2">
                        <Button
                          size="sm"
                          variant="outline"
                          className="bg-white/90 hover:bg-white"
                          onClick={() => onPreviewImage(image)}
                        >
                          <Eye className="h-3 w-3 mr-1" />
                          View
                        </Button>
                        <Button
                          size="sm"
                          variant="outline"
                          className="bg-white/90 hover:bg-white"
                          onClick={() => promoteToFeatured(image)}
                        >
                          <ArrowUp className="h-3 w-3 mr-1" />
                          Primary
                        </Button>
                        <Button
                          size="sm"
                          variant="destructive"
                          className="bg-white/90 hover:bg-white text-red-500 hover:text-red-600"
                          onClick={() => setSecondaryImages(secondaryImages.filter(img => img.id !== image.id))}
                        >
                          <X className="h-3 w-3 mr-1" />
                          Remove
                        </Button>
                      </div>
                    </div>
                  ))}
                </div>

                {secondaryImages.length > 1 && (
                  <Button 
                    variant="outline" 
                    size="sm" 
                    className="mt-4 text-red-600 hover:text-red-700"
                    onClick={() => {
                      if (window.confirm('Are you sure you want to remove all secondary images?')) {
                        setSecondaryImages([]);
                        toast({
                          title: 'Secondary images cleared',
                          description: 'All secondary images have been removed.',
                        });
                      }
                    }}
                  >
                    <Trash2 className="h-3 w-3 mr-1" />
                    Clear All Secondary Images
                  </Button>
                )}
              </div>
            ) : (
              <div className="flex items-center justify-center bg-green-50 border-2 border-dashed border-green-200 rounded-md aspect-video w-full max-w-md">
                <div className="text-center p-4">
                  <ImageIcon className="h-10 w-10 mx-auto text-green-300" />
                  <p className="mt-2 text-sm text-green-500">No secondary images selected</p>
                  <p className="text-xs text-green-400">Choose images below and select "Secondary"</p>
                </div>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
}

client/src/components/ShopifyConnectionC.content:
import { useState, useEffect } from "react";
import { useQuery } from "@tanstack/react-query";
import { apiRequest } from "@/lib/queryClient";
import { queryClient } from "@/lib/queryClient";
import { format } from "date-fns";
import { ShopifyConnection, SyncActivity } from "@shared/schema";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Label } from "@/components/ui/label";
import { CheckCircle, History, Link2, RefreshCw } from "lucide-react";
import { useToast } from "@/hooks/use-toast";
import { Skeleton } from "@/components/ui/skeleton";

export default function ShopifyConnectionCard() {
  const { toast } = useToast();
  const [selectedBlog, setSelectedBlog] = useState<string>("");
  const [blogs, setBlogs] = useState<{id: string, title: string}[]>([]);
  const [isSyncing, setIsSyncing] = useState(false);
  const [isDisconnecting, setIsDisconnecting] = useState(false);

  // Connection form states
  const [showConnectionForm, setShowConnectionForm] = useState(false);
  const [storeName, setStoreName] = useState("");
  const [accessToken, setAccessToken] = useState("");
  const [isConnecting, setIsConnecting] = useState(false);

  const { data: connectionData, isLoading: isConnectionLoading } = useQuery<{ connection: ShopifyConnection }>({
    queryKey: ["/api/shopify/connection"],
  });

  const { data: activitiesData, isLoading: isActivitiesLoading } = useQuery<{ activities: SyncActivity[] }>({
    queryKey: ["/api/sync-activities"],
  });

  const { data: blogsData, isLoading: isBlogsLoading } = useQuery<{ blogs: { id: string, title: string }[] }>({
    queryKey: ["/api/shopify/blogs"],
    enabled: !!connectionData?.connection?.isConnected,
  });

  useEffect(() => {
    if (blogsData?.blogs) {
      setBlogs(blogsData.blogs);
    }
  }, [blogsData]);

  useEffect(() => {
    if (connectionData?.connection?.defaultBlogId) {
      setSelectedBlog(connectionData.connection.defaultBlogId);
    }
  }, [connectionData]);

  const handleSyncNow = async () => {
    setIsSyncing(true);

    try {
      await apiRequest("POST", "/api/shopify/sync", {});

      queryClient.invalidateQueries({ queryKey: ["/api/shopify/connection"] });
      queryClient.invalidateQueries({ queryKey: ["/api/sync-activities"] });

      toast({
        title: "Sync Complete",
        description: "Successfully synchronized with Shopify",
        variant: "success",
      });
    } catch (error) {
      toast({
        title: "Sync Failed",
        description: error.message || "Failed to sync with Shopify",
        variant: "destructive",
      });
    } finally {
      setIsSyncing(false);
    }
  };

  const handleDisconnect = async () => {
    if (!window.confirm("Are you sure you want to disconnect your Shopify store?")) {
      return;
    }

    setIsDisconnecting(true);

    try {
      await apiRequest("POST", "/api/shopify/disconnect", {});

      queryClient.invalidateQueries({ queryKey: ["/api/shopify/connection"] });

      toast({
        title: "Store Disconnected",
        description: "Your Shopify store has been disconnected",
      });
    } catch (error) {
      toast({
        title: "Error",
        description: error.message || "Failed to disconnect store",
        variant: "destructive",
      });
    } finally {
      setIsDisconnecting(false);
    }
  };

  const handleChangeBlog = async (blogId: string) => {
    setSelectedBlog(blogId);

    try {
      await apiRequest("POST", "/api/shopify/default-blog", { blogId });

      queryClient.invalidateQueries({ queryKey: ["/api/shopify/connection"] });

      toast({
        title: "Default Blog Updated",
        description: "Your default blog has been updated",
        variant: "success",
      });
    } catch (error) {
      toast({
        title: "Error",
        description: error.message || "Failed to update default blog",
        variant: "destructive",
      });
    }
  };

  const handleShowConnectionForm = () => {
    setShowConnectionForm(true);
  };

  const handleConnectToShopify = async () => {
    if (!storeName || !accessToken) {
      toast({
        title: "Missing Information",
        description: "Please fill in all fields",
        variant: "destructive",
      });
      return;
    }

    setIsConnecting(true);

    try {
      // Format store name to ensure it has myshopify.com
      let formattedStoreName = storeName.trim();
      if (!formattedStoreName.includes("myshopify.com")) {
        formattedStoreName = `${formattedStoreName}.myshopify.com`;
      }

      await apiRequest("POST", "/api/shopify/connection", {
        storeName: formattedStoreName,
        accessToken: accessToken,
        isConnected: true,
      });

      queryClient.invalidateQueries({ queryKey: ["/api/shopify/connection"] });

      toast({
        title: "Connected Successfully",
        description: "Your Shopify store has been connected",
        variant: "success",
      });

      // Reset form
      setStoreName("");
      setAccessToken("");
      setShowConnectionForm(false);
    } catch (error) {
      toast({
        title: "Connection Failed",
        description: error.message || "Failed to connect to Shopify",
        variant: "destructive",
      });
    } finally {
      setIsConnecting(false);
    }
  };

  const connection = connectionData?.connection;
  const activities = activitiesData?.activities || [];

  const isConnected = connection?.isConnected;

  if (isConnectionLoading) {
    return (
      <Card>
        <CardHeader className="border-b border-neutral-200">
          <CardTitle>Shopify Connection</CardTitle>
          <CardDescription>
            Manage your Shopify store connection
          </CardDescription>
        </CardHeader>
        <CardContent className="pt-6">
          <Skeleton className="h-20 w-full mb-4" />
          <Skeleton className="h-8 w-full mb-4" />
          <Skeleton className="h-10 w-full mb-4" />
          <Skeleton className="h-32 w-full" />
        </CardContent>
      </Card>
    );
  }

  return (
    <Card>
      <CardHeader className="border-b border-neutral-200">
        <CardTitle>Shopify Connection</CardTitle>
        <CardDescription>
          Manage your Shopify store connection
        </CardDescription>
      </CardHeader>
      <CardContent className="pt-6">
        {isConnected ? (
          <>
            <div className="flex items-center p-4 mb-4 bg-green-50 rounded-md">
              <CheckCircle className="text-green-500 mr-3 h-5 w-5" />
              <div>
                <h4 className="text-sm font-medium text-green-500">Connected</h4>
                <p className="text-sm text-neutral-600 mt-1">{connection?.storeName}</p>
              </div>
            </div>

            <div className="space-y-4">
              <div>
                <Label>Default Blog</Label>
                <div className="mt-1 flex rounded-md shadow-sm">
                  <Select value={selectedBlog} onValueChange={handleChangeBlog}>
                    <SelectTrigger>
                      <SelectValue placeholder="Select a blog" />
                    </SelectTrigger>
                    <SelectContent>
                      {isBlogsLoading ? (
                        <SelectItem value="loading" disabled>Loading blogs...</SelectItem>
                      ) : blogs.length > 0 ? (
                        blogs.map((blog) => (
                          <SelectItem key={blog.id} value={blog.id}>{blog.title}</SelectItem>
                        ))
                      ) : (
                        <SelectItem value="none" disabled>No blogs found</SelectItem>
                      )}
                    </SelectContent>
                  </Select>
                </div>
              </div>
            </div>

            <div className="mt-5 grid grid-cols-2 gap-3">
              <Button
                variant="outline"
                onClick={handleDisconnect}
                disabled={isDisconnecting}
              >
                <Link2 className="mr-2 h-4 w-4" />
                {isDisconnecting ? "Disconnecting..." : "Disconnect"}
              </Button>
              <Button
                onClick={handleSyncNow}
                disabled={isSyncing}
              >
                <RefreshCw className={`mr-2 h-4 w-4 ${isSyncing ? "animate-spin" : ""}`} />
                {isSyncing ? "Syncing..." : "Sync Now"}
              </Button>
            </div>

            <div className="mt-4 pt-4 border-t border-neutral-200">
              <h4 className="text-sm font-medium text-neutral-900 mb-3">Last Sync Activity</h4>

              {isActivitiesLoading ? (
                <div className="space-y-2">
                  <Skeleton className="h-5 w-full" />
                  <Skeleton className="h-5 w-full" />
                </div>
              ) : activities.length > 0 ? (
                <div className="space-y-2">
                  {activities.slice(0, 2).map((activity) => (
                    <div key={activity.id} className="flex space-x-2 text-sm">
                      <History className="text-neutral-400 h-4 w-4" />
                      <span className="text-neutral-500">
                        {format(new Date(activity.timestamp), "MMM d 'at' h:mm a")}
                      </span>
                      <span className="text-neutral-700">{activity.activity}</span>
                    </div>
                  ))}
                </div>
              ) : (
                <p className="text-sm text-neutral-500">No recent activity</p>
              )}
            </div>
          </>
        ) : (
          <div className="p-6">
            {showConnectionForm ? (
              <div>
                <h4 className="text-lg font-medium text-neutral-900 mb-4">Connect to Shopify</h4>
                <div className="space-y-4">
                  <div>
                    <Label htmlFor="storeName">Store Name</Label>
                    <div className="mt-1">
                      <input
                        type="text"
                        id="storeName"
                        className="px-3 py-2 block w-full rounded-md border border-gray-300 shadow-sm focus:border-blue-500 focus:ring-blue-500 sm:text-sm"
                        placeholder="your-store.myshopify.com"
                        value={storeName}
                        onChange={(e) => setStoreName(e.target.value)}
                      />
                      <p className="mt-1 text-xs text-neutral-500">Your Shopify store name (e.g., your-store.myshopify.com)</p>
                    </div>
                  </div>

                  <div>
                    <Label htmlFor="accessToken">Access Token</Label>
                    <div className="mt-1">
                      <input
                        type="password"
                        id="accessToken"
