                <dd>
                  <div className="text-lg font-semibold text-neutral-900">
                    {value}
                  </div>
                </dd>
              </dl>
            </div>
          </div>
        </div>
      </CardContent>
    </Card>
  );
}

client/src/components/StoreSelector.tsx.content:
import { useQuery, useQueryClient } from '@tanstack/react-query';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { Store, ExternalLink, Settings, RefreshCw } from 'lucide-react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { useStore } from '../contexts/StoreContext';

interface StoreSelectorProps {
  onStoreChange?: (storeId: number) => void;
}

export function StoreSelector({ onStoreChange }: StoreSelectorProps) {
  const queryClient = useQueryClient();
  const { currentStore, selectedStoreId, stores, isLoading, selectStore, refreshStores } = useStore();

  const handleStoreChange = (storeId: string) => {
    const id = parseInt(storeId);
    console.log(`StoreSelector: Switching to store ID ${id}`);

    // Clear all cache completely before switching
    queryClient.clear();

    selectStore(id);
    onStoreChange?.(id);

    console.log(`StoreSelector: Store switched to ${id}, cache cleared`);
  };

  const getStoreName = (shopName: string) => {
    return shopName.replace('.myshopify.com', '');
  };

  const getStoreStatus = (store: any) => {
    if (!store.isConnected) return { label: 'Disconnected', variant: 'destructive' as const };
    if (store.planName) return { label: store.planName, variant: 'default' as const };
    return { label: 'Connected', variant: 'secondary' as const };
  };

  if (isLoading) {
    return (
      <Card className="w-full">
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Store className="h-5 w-5" />
            Loading stores...
          </CardTitle>
        </CardHeader>
      </Card>
    );
  }

  return (
    <Card className="w-full">
      <CardHeader>
        <CardTitle className="flex items-center gap-2">
          <Store className="h-5 w-5" />
          Store Management
          <Button
            variant="ghost"
            size="sm"
            onClick={refreshStores}
            className="ml-auto"
          >
            <RefreshCw className="h-4 w-4" />
          </Button>
        </CardTitle>
      </CardHeader>
      <CardContent className="space-y-4">
        {/* Current Active Store */}
        {currentStore && (
          <div className="p-4 bg-blue-50 rounded-lg border border-blue-200">
            <div className="flex items-center justify-between">
              <div>
                <h3 className="font-semibold text-blue-900">Currently Active Store</h3>
                <p className="text-blue-700">{getStoreName(currentStore.shopName)}</p>
                <p className="text-sm text-blue-600">
                  Store ID: {currentStore.id} • Connected: {currentStore.isConnected ? 'Yes' : 'No'}
                </p>
              </div>
              <div className="flex items-center gap-2">
                <Badge variant="secondary">Active</Badge>
                <Button
                  variant="outline"
                  size="sm"
                  onClick={() => window.open(`https://${currentStore.shopName}/admin`, '_blank')}
                >
                  <ExternalLink className="h-4 w-4 mr-1" />
                  Admin
                </Button>
              </div>
            </div>
          </div>
        )}

        {/* Store Selector */}
        {stores.length > 1 && (
          <div className="space-y-2">
            <label className="text-sm font-medium">Switch Store Context</label>
            <Select value={selectedStoreId?.toString()} onValueChange={handleStoreChange}>
              <SelectTrigger>
                <SelectValue placeholder="Select a store to work with" />
              </SelectTrigger>
              <SelectContent>
                {stores.map((store) => (
                  <SelectItem key={store.id} value={store.id.toString()}>
                    <div className="flex items-center justify-between w-full">
                      <span>{getStoreName(store.shopName)}</span>
                      <Badge variant={getStoreStatus(store).variant} className="ml-2">
                        {getStoreStatus(store).label}
                      </Badge>
                    </div>
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>
        )}

        {/* Connected Stores List */}
        <div className="space-y-2">
          <h4 className="text-sm font-medium">All Connected Stores ({stores.length})</h4>
          <div className="space-y-2">
            {stores.map((store) => {
              const status = getStoreStatus(store);
              const isSelected = store.id === selectedStoreId;
              return (
                <div key={store.id} className={`flex items-center justify-between p-3 rounded-lg ${
                  isSelected ? 'bg-blue-50 border border-blue-200' : 'bg-gray-50'
                }`}>
                  <div className="flex-1">
                    <div className="flex items-center gap-2">
                      <span className="font-medium">{getStoreName(store.shopName)}</span>
                      <Badge variant={status.variant}>{status.label}</Badge>
                      {isSelected && <Badge variant="outline">Selected</Badge>}
                    </div>
                    <p className="text-sm text-gray-600">
                      ID: {store.id} • Installed: {new Date(store.installedAt).toLocaleDateString()}
                      {store.lastSynced && (
                        <span className="ml-2">
                          • Last sync: {new Date(store.lastSynced).toLocaleString()}
                        </span>
                      )}
                    </p>
                  </div>
                  <div className="flex items-center gap-2">
                    <Button
                      variant="outline"
                      size="sm"
                      onClick={() => window.open(`https://${store.shopName}/admin`, '_blank')}
                    >
                      <ExternalLink className="h-4 w-4 mr-1" />
                      Admin
                    </Button>
                    {!isSelected && (
                      <Button
                        variant="outline"
                        size="sm"
                        onClick={() => handleStoreChange(store.id.toString())}
                      >
                        <Settings className="h-4 w-4 mr-1" />
                        Select
                      </Button>
                    )}
                  </div>
                </div>
              );
            })}
          </div>
        </div>

        {/* Installation Instructions */}
        <div className="mt-6 p-4 bg-gray-50 rounded-lg">
          <h4 className="font-medium mb-2">Install App in New Store</h4>
          <p className="text-sm text-gray-600 mb-3">
            To install this app in a new Shopify store, use this URL format:
          </p>
          <code className="block p-2 bg-gray-100 rounded text-sm break-all">
            {window.location.origin}/oauth/install?shop=STORE_NAME
          </code>
          <p className="text-xs text-gray-500 mt-2">
            Replace STORE_NAME with the actual store name (without .myshopify.com)
          </p>
        </div>
      </CardContent>
    </Card>
  );
}

client/src/components/TitleSelector.tsx.content:
import React, { useState, useEffect } from 'react';
import { Button } from '@/components/ui/button';
import { Card } from '@/components/ui/card';
import { Loader2 } from 'lucide-react';
import { apiRequest } from '@/lib/queryClient';
import { useToast } from '@/hooks/use-toast';

export interface TitleSelectionProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  onTitleSelected: (title: string) => void;
  selectedKeywords: any[];
  productTitle?: string;
  targetAudience?: string;
  buyerPersona?: string;
}

export default function TitleSelector({
  open,
  onOpenChange,
  onTitleSelected,
  selectedKeywords,
  productTitle,
  targetAudience,
  buyerPersona
}: TitleSelectionProps) {
  const [titleSuggestions, setTitleSuggestions] = useState<string[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const { toast } = useToast();

  // Generate title suggestions when the component is opened
  useEffect(() => {
    if (open && selectedKeywords.length > 0) {
      generateTitles();
    }
  }, [open, selectedKeywords]);

  const generateTitles = async () => {
    setIsLoading(true);
    setError(null);

    // Log the request data for debugging
    const requestData = {
      keywords: selectedKeywords.map(k => k.keyword),
      keywordData: selectedKeywords,
      productTitle: productTitle,
      targetAudience: targetAudience,
      buyerPersona: buyerPersona
    };

    console.log("Generating title suggestions with data:", requestData);

    try {
      const response = await apiRequest({
        url: '/api/admin/title-suggestions',
        method: 'POST',
        data: requestData
      });

      console.log("Title suggestions response:", response);

      if (response.success && response.titles && response.titles.length > 0) {
        console.log("Setting new title suggestions:", response.titles);
        setTitleSuggestions(response.titles);
      } else {
        console.error("Failed to get valid title suggestions:", response);
        setError('Could not generate title suggestions');
        toast({
          title: 'Error',
          description: 'Failed to generate title suggestions',
          variant: 'destructive'
        });
      }
    } catch (err: any) {
      console.error('Title suggestion error:', err);
      setError(err.message || 'An unexpected error occurred');
      toast({
        title: 'Error',
        description: err.message || 'Failed to generate title suggestions',
        variant: 'destructive'
      });
    } finally {
      setIsLoading(false);
    }
  };

  const handleTitleSelect = (title: string) => {
    onTitleSelected(title);
    onOpenChange(false);
  };

  return (
    <div className="space-y-4 py-4">
      {isLoading ? (
        <div className="flex flex-col items-center justify-center p-8">
          <Loader2 className="h-8 w-8 text-blue-500 animate-spin" />
          <p className="mt-4 text-center text-muted-foreground">
            Generating title suggestions based on your selected keywords...
          </p>
        </div>
      ) : error ? (
        <div className="text-center p-4 space-y-4">
          <p className="text-red-500">{error}</p>
          <Button onClick={generateTitles}>Try Again</Button>
        </div>
      ) : (
        <>
          <div>
            <h3 className="text-lg font-semibold mb-3 text-slate-800">Choose an SEO-optimized title:</h3>
            <div className="grid gap-3 md:grid-cols-2">
              {titleSuggestions.length > 0 ? (
                titleSuggestions.map((title, index) => (
                  <Card
                    key={index}
                    className={`p-4 hover:bg-blue-50 cursor-pointer transition-colors border-2 ${index < 3 ? 'border-blue-200' : 'border-transparent'}`}
                    onClick={() => handleTitleSelect(title)}
                  >
                    <div className="flex items-start">
                      <div className="flex-1">
                        <h3 className="font-medium text-md text-blue-700">{title}</h3>
                        {index < 3 && (
                          <span className="inline-flex items-center mt-1 px-2 py-0.5 rounded text-xs font-medium bg-blue-100 text-blue-800">
                            {index === 0 ? 'Best for SEO' : index === 1 ? 'Trending format' : 'High CTR'}
                          </span>
                        )}
                      </div>
                      <span className="ml-2 text-sm text-slate-400 opacity-75">#{index + 1}</span>
                    </div>
                  </Card>
                ))
              ) : (
                <div className="text-center p-4 col-span-2">
                  <p>No title suggestions available</p>
                  <Button 
                    onClick={generateTitles} 
                    className="mt-2"
                    disabled={selectedKeywords.length === 0}
                  >
                    Generate Titles
                  </Button>
                </div>
              )}
            </div>
          </div>

          <div className="flex justify-between pt-4">
            <Button 
              variant="outline" 
              onClick={() => {
                onOpenChange(false);
              }}
            >
              Cancel
            </Button>

            <Button 
              onClick={generateTitles}
              disabled={isLoading || selectedKeywords.length === 0}
            >
              Generate New Suggestions
            </Button>
          </div>
        </>
      )}
    </div>
  );
}

