            productImages.push({
              id: `product-${product.id}-main`,
              url: imageUrl,
              width: 500,
              height: 500,
              alt: product.title || 'Product image',
              src: {
                original: imageUrl,
                large: imageUrl,
                medium: imageUrl,
                small: imageUrl,
                thumbnail: imageUrl
              },
              selected: false,
              source: 'shopify'
            });
          }
        }

        // Add additional product images
        if (product.images && Array.isArray(product.images)) {
          product.images.forEach((image, index) => {
            if (image.src && (!product.image || image.id !== product.image.id)) {
              // Skip the main image (already added above)
              const imageUrl = image.src;
              if (!uniqueImageUrls.has(imageUrl)) {
                uniqueImageUrls.add(imageUrl);
                productImages.push({
                  id: `product-${product.id}-image-${index}`,
                  url: imageUrl,
                  width: 500,
                  height: 500,
                  alt: image.alt || `${product.title} - Image ${index + 1}`,
                  src: {
                    original: imageUrl,
                    large: imageUrl,
                    medium: imageUrl,
                    small: imageUrl,
                    thumbnail: imageUrl
                  },
                  selected: false,
                  source: 'shopify'
                });
              }
            }
          });
        }

        // Add variant images if requested
        if (includeVariants && product.variants && Array.isArray(product.variants)) {
          product.variants.forEach((variant, variantIndex) => {
            if (variant.image && variant.image.src) {
