      </div>

      <PostList
        queryKey="/api/posts"
        title="All Posts"
        onEditPost={handleEditPost}
      />

      <CreatePostModal
        open={createPostModalOpen}
        onOpenChange={setCreatePostModalOpen}
        initialData={selectedPost}
      />
