  const [editedTemplateTopics, setEditedTemplateTopics] = useState<string>("");
  // Get templates from localStorage if available
  const getInitialTemplates = (): Template[] => {
    try {
      // Try to load templates from localStorage
      const savedTemplates = localStorage.getItem('contentTemplates');
      if (savedTemplates) {
        console.log("Loading templates from localStorage");
        return JSON.parse(savedTemplates);
      }
    } catch (error) {
      console.error("Error loading templates from localStorage:", error);
    }

    // Default templates if none in localStorage
    return [
      {
        id: 1,
        name: "Product Review",
        description: "Template for reviewing products with pros, cons, and ratings.",
        category: "Reviews"
      },
      {
        id: 2,
        name: "How-To Guide",
        description: "Step-by-step instructions for teaching a skill or process.",
        category: "Educational"
      },
      {
        id: 3,
        name: "Industry News",
        description: "Format for reporting on industry trends and developments.",
        category: "News"
      },
      {
        id: 4,
        name: "Product Comparison",
        description: "Side-by-side comparison of similar products or services.",
        category: "Reviews"
      },
      {
        id: 5,
        name: "Seasonal Promotion",
        description: "Promotional content for seasonal sales and special events.",
        category: "Marketing"
      },
      {
        id: 6,
        name: "Customer Story",
        description: "Format for highlighting customer success stories.",
        category: "Case Studies"
      }
    ];
  };

  const [templates, setTemplates] = useState<Template[]>(getInitialTemplates());

  // Load template content from localStorage when component mounts
  useEffect(() => {
    try {
      const savedTemplateContent = localStorage.getItem('templateContents');
      if (savedTemplateContent) {
        console.log("Loading template content from localStorage");
        const loadedContent = JSON.parse(savedTemplateContent);
        // Apply the loaded content to the global templateContent object
        Object.keys(loadedContent).forEach(key => {
          const templateId = parseInt(key);
          templateContent[templateId] = loadedContent[templateId];
        });
        console.log("Template content loaded successfully");
      }
    } catch (error) {
      console.error("Error loading template content from localStorage:", error);
    }
  }, []);
  const [generationResults, setGenerationResults] = useState<{
    success: number;
    failed: number;
    total: number;
    inProgress: boolean;
  }>({
    success: 0,
    failed: 0,
    total: 0,
    inProgress: false
  });

  // Handle template usage
  const handleUseTemplate = (template: Template) => {
    setSelectedTemplate(template);
    setIsDialogOpen(true);
  };

  // Handle template editing
  const handleEditTemplate = (template: Template) => {
    setSelectedTemplate(template);
    setIsEditDialogOpen(true);
  };

  // Apply template with topic
  const handleApplyTemplate = async (topic: string, templateId: number) => {
    try {
      // Get the content structure for this template
      const templateData = templateContent[templateId];
      if (!templateData) {
        throw new Error("Template content not found");
      }

      // Get the custom AI prompt for this template
      const customPrompt = templateData.aiPrompt;

      // Generate a title based on topic and template
      const selectedTemplate = templates.find(t => t.id === templateId);
      let title = "";

      console.log("Creating blog post from template with topic:", topic);

      switch (templateId) {
        case 1: // Product Review
          title = `${topic} Review: Is It Worth Your Money?`;
          break;
        case 2: // How-To Guide  
          title = `How to Master ${topic}: A Complete Guide`;
          break;
        case 3: // Industry News
          title = `${topic} Trends: What's New in ${new Date().getFullYear()}`;
          break;
        case 4: // Product Comparison
          const parts = topic.split(' vs ');
          title = parts.length > 1 
            ? `${parts[0]} vs ${parts[1]}: Which One is Better?`
            : `${topic} Comparison: Finding the Best Option`;
          break;
        case 5: // Seasonal Promotion
          title = `${topic} Special: Exclusive Deals You Can't Miss`;
          break;
        case 6: // Customer Story
          title = `How Our Customer Achieved Success with ${topic}`;
          break;
        default:
          title = `${topic} - ${selectedTemplate?.name || 'Blog Post'}`;
      }

      // Create content by replacing placeholders in the template
      let content = templateData.structure;

      // Replace topic-related placeholders
      content = content.replace(/\[Product Name\]/g, topic)
                       .replace(/\[Industry\]/g, topic)
                       .replace(/\[Season\/Holiday\]/g, topic)
                       .replace(/\[Accomplish Task\]/g, topic)
                       .replace(/\[Year\]/g, new Date().getFullYear().toString())
                       // Add more comprehensive replacements for all common placeholders
                       .replace(/\[Trend Name\]/g, `${topic} Optimization`)
                       .replace(/\[Explanation of the trend and its impact\]/g, `The growing focus on ${topic} has transformed how businesses approach their e-commerce strategy. Companies that effectively optimize for ${topic} see higher conversion rates and customer satisfaction.`)
                       .replace(/\[Quotes or insights from industry experts\]/g, `Industry expert Jane Smith notes, "${topic} is the future of e-commerce." Meanwhile, John Davis from E-commerce Today predicts that "${topic} adoption will increase by 40% next year."`)
                       .replace(/\[Practical implications and action steps\]/g, `To stay competitive, implement ${topic} strategies immediately. Start by assessing your current performance, identify gaps, and create a roadmap for improvement.`)
                       .replace(/\[Future predictions and preparation strategies\]/g, `The ${topic} landscape will continue to evolve rapidly. Stay ahead by subscribing to industry newsletters, attending webinars, and investing in ongoing training for your team.`);

      // If using AI-generated content based on the template's custom prompt
      if (customPrompt) {
        try {
          console.log(`Using custom prompt for template: ${selectedTemplate?.name}`);
          console.log(`Custom prompt content: ${customPrompt}`);

          console.log("Making API request to /api/generate-content");
          const openaiResponse = await apiRequest({
            url: "/api/generate-content",
            method: "POST",
            data: {
              topic,
              customPrompt
            }
          });

          console.log("API Response received:", openaiResponse);

          if (openaiResponse && openaiResponse.success) {
            console.log("Successfully generated content with custom prompt");

            if (openaiResponse.content) {
              console.log(`Content received, length: ${openaiResponse.content.length} characters`);
              console.log("Content preview:", openaiResponse.content.substring(0, 100) + "...");
              content = openaiResponse.content;
            } else {
              console.error("API returned success but content is missing");
            }

            // Use the AI-generated title if available
            if (openaiResponse.title) {
              console.log(`Using AI-generated title: "${openaiResponse.title}"`);
              title = openaiResponse.title;
            } else {
              console.log("API response missing title, using default");
            }
          } else {
            console.error("API call failed or returned unsuccessful status:", openaiResponse);
          }
        } catch (promptError) {
          console.error("Error generating content with custom prompt:", promptError);
          // Continue with the template content as fallback
        }
      } else {
        console.log("No custom prompt provided, using template content only");
      }

      // Create synthetic tags based on topic and template type
      const tags = [
        topic,
        selectedTemplate?.category || "",
        selectedTemplate?.name || ""
      ].filter(Boolean);

      // Create a new post draft with this content
      const response = await apiRequest({
        url: "/api/posts",
        method: "POST",
        data: {
          title,
          content,
          status: "draft",
          tags: tags.join(","), // Tags is a text field in the schema, so join array to string
          category: selectedTemplate?.category || "General",
          storeId: null, // Use the default store connection
          author: "Template System",
          // Add these fields explicitly to avoid validation errors
          scheduledDate: null,
          publishedDate: null
        }
      });

      // Server returns the created post object
      if (response) {
        toast({
          title: "Template Applied",
          description: "New draft created from template",
        });

        // Navigate to blog posts page
        setLocation("/blog-posts");
      }
    } catch (error) {
      console.error("Error applying template:", error);
      toast({
        title: "Error",
        description: "Failed to apply template",
        variant: "destructive",
      });
    }
  };

  // Save edited template
  const handleSaveTemplate = (templateId: number, structure: string, topics: string[], aiPrompt: string) => {
    try {
      if (!templateId) {
        throw new Error("Invalid template ID");
      }

      console.log(`Saving template ${templateId} with updated content`);
      console.log("Updated structure (first 50 chars):", structure.substring(0, 50) + "...");
      console.log("Updated AI prompt (first 50 chars):", aiPrompt.substring(0, 50) + "...");

      // Create a deep copy to ensure state update
      const updatedContent = {
        structure: structure,
        topics: [...topics],
        aiPrompt: aiPrompt
      };

      // In a real app with a database, we would save this via an API
      // For now, update the local templateContent object
      // Create a new reference to ensure React detects the change
      const newTemplateContent = { ...templateContent };
      newTemplateContent[templateId] = updatedContent;

      // Update the template content directly
      templateContent[templateId] = updatedContent;

      // Save templates to localStorage for persistence
      try {
        // Need to save both templates and templateContent
        localStorage.setItem('contentTemplates', JSON.stringify(templates));
        localStorage.setItem('templateContents', JSON.stringify(templateContent));
        console.log("Templates and content saved to localStorage after update");
      } catch (storageError) {
        console.error("Error saving templates to localStorage:", storageError);
      }

      toast({
        title: "Template Updated",
        description: "Template content has been updated successfully.",
      });
    } catch (error) {
      console.error("Error saving template:", error);
      toast({
        title: "Error Updating Template",
        description: "There was a problem updating the template. Please try again.",
        variant: "destructive"
      });
    } finally {
      setIsEditDialogOpen(false);
    }
  };

  // Handle creating a new template
  const handleCreateNewTemplate = (name: string, description: string, category: string, structure: string, topics: string[], aiPrompt: string) => {
    try {
      // Generate a new template ID (max current ID + 1)
      const newId = Math.max(...templates.map(t => t.id), 0) + 1;

      console.log(`Creating new template with ID ${newId}: ${name}`);

      // Create new template object
      const newTemplate: Template = {
        id: newId,
        name,
        description,
        category
      };

      // Create deep copy of template content to prevent reference issues
      const newContent = {
        structure: structure,
        topics: [...topics],
        aiPrompt: aiPrompt
      };

      // Create a new templates array and a new templateContent object to ensure state updates
      const updatedTemplates = [...templates, newTemplate];
      const updatedTemplateContent = { ...templateContent };
      updatedTemplateContent[newId] = newContent;

      // Update state with the new values
      setTemplates(updatedTemplates);

      // In a real app, we would save this to a database
      // For now, update the local templateContent record and save to localStorage
      console.log(`Setting template content for ID ${newId}`);
      console.log("Template structure:", structure.substring(0, 50) + "...");
      console.log("Template AI prompt:", aiPrompt.substring(0, 50) + "...");

      // Add template content to global object - needs careful handling
      templateContent[newId] = newContent;

      // Save templates to localStorage for persistence
      try {
        // Need to save both templates and templateContent
        localStorage.setItem('contentTemplates', JSON.stringify(updatedTemplates));
        localStorage.setItem('templateContents', JSON.stringify(templateContent));
        console.log("Templates and content saved to localStorage after create");
      } catch (storageError) {
        console.error("Error saving templates to localStorage:", storageError);
      }

      toast({
        title: "Template Created",
        description: `New template "${name}" has been created successfully.`,
      });
    } catch (error) {
      console.error("Error creating template:", error);
      toast({
        title: "Error Creating Template",
        description: "There was a problem creating the template. Please try again.",
        variant: "destructive"
      });
    } finally {
      setIsCreateDialogOpen(false);
    }
  };

  const handleCreateTemplate = () => {
    setSelectedTemplate(null);
    setIsCreateDialogOpen(true);
  };

  // Open bulk generation dialog
  const handleOpenBulkGeneration = () => {
    setIsBulkDialogOpen(true);
  };

  // Process bulk article generation
  const handleBulkGeneration = async (keywords: string[], templateId: number) => {
    // Reset results
    setGenerationResults({
      success: 0,
      failed: 0,
      total: keywords.length,
      inProgress: true
    });

    let successCount = 0;
    let failedCount = 0;

    // Get template data
    const templateData = templateContent[templateId];
    const selectedTemplate = templates.find(t => t.id === templateId);
    const customPrompt = templateData?.aiPrompt;

    if (!templateData || !selectedTemplate) {
      toast({
        title: "Error",
        description: "Template not found",
        variant: "destructive",
      });
      return;
    }

    // Process each keyword
    for (const keyword of keywords) {
      try {
        // Generate title based on template type
        let title = "";

        switch (templateId) {
          case 1: // Product Review
            title = `${keyword} Review: Is It Worth Your Money?`;
            break;
          case 2: // How-To Guide  
            title = `How to Master ${keyword}: A Complete Guide`;
            break;
          case 3: // Industry News
            title = `${keyword} Trends: What's New in ${new Date().getFullYear()}`;
            break;
          case 4: // Product Comparison
            const parts = keyword.split(' vs ');
            title = parts.length > 1 
              ? `${parts[0]} vs ${parts[1]}: Which One is Better?`
              : `${keyword} Comparison: Finding the Best Option`;
            break;
          case 5: // Seasonal Promotion
            title = `${keyword} Special: Exclusive Deals You Can't Miss`;
            break;
          case 6: // Customer Story
            title = `How Our Customer Achieved Success with ${keyword}`;
            break;
          default:
            title = `${keyword} - ${selectedTemplate?.name || 'Blog Post'}`;
        }

        // Create initial content by replacing placeholders in the template
        let content = templateData.structure;

        // Replace topic-related placeholders
        content = content.replace(/\[Product Name\]/g, keyword)
                        .replace(/\[Industry\]/g, keyword)
                        .replace(/\[Season\/Holiday\]/g, keyword)
                        .replace(/\[Accomplish Task\]/g, keyword)
                        .replace(/\[Year\]/g, new Date().getFullYear().toString())
                        // Add more comprehensive replacements for all common placeholders
                        .replace(/\[Trend Name\]/g, `${keyword} Optimization`)
                        .replace(/\[Explanation of the trend and its impact\]/g, `The growing focus on ${keyword} has transformed how businesses approach their e-commerce strategy. Companies that effectively optimize for ${keyword} see higher conversion rates and customer satisfaction.`)
                        .replace(/\[Quotes or insights from industry experts\]/g, `Industry expert Jane Smith notes, "${keyword} is the future of e-commerce." Meanwhile, John Davis from E-commerce Today predicts that "${keyword} adoption will increase by 40% next year."`)
                        .replace(/\[Practical implications and action steps\]/g, `To stay competitive, implement ${keyword} strategies immediately. Start by assessing your current performance, identify gaps, and create a roadmap for improvement.`)
                        .replace(/\[Future predictions and preparation strategies\]/g, `The ${keyword} landscape will continue to evolve rapidly. Stay ahead by subscribing to industry newsletters, attending webinars, and investing in ongoing training for your team.`);

        // Use AI-generated content with the template's custom prompt if available
        if (customPrompt) {
          try {
            console.log(`Using custom prompt for bulk generation with template: ${selectedTemplate?.name}`);

            // Use the bulkGenerateContent method from the OpenAI service
            const bulkResponse = await apiRequest({
              url: "/api/generate-content/bulk",
              method: "POST",
              data: {
                topics: [keyword],
                templateId: templateId,
                customPrompt: customPrompt
              }
            });

            console.log("Bulk generation response:", bulkResponse);

            if (bulkResponse && bulkResponse.success) {
              console.log("Bulk generation response:", bulkResponse);

              // Check if there are posts in the response
              if (bulkResponse.posts && bulkResponse.posts.length > 0) {
                // Update with AI-generated content
                const generatedPost = bulkResponse.posts[0];
                if (generatedPost) {
                  // Extract content from the generated post
                  title = generatedPost.title || title;
                  // Make sure content is not empty
                  if (generatedPost.content && generatedPost.content.length > 0) {
                    content = generatedPost.content;
                    console.log("Successfully extracted content from bulk generation, length:", content.length);
                  } else {
                    console.warn("Generated post has empty content!");
                  }
                }
              } else {
                console.warn("Bulk generation API call succeeded but returned no posts");
              }
            } else {
              console.warn("Bulk generation API call failed or returned unsuccessful response");
            }
          } catch (promptError) {
            console.error("Error generating content with custom prompt for bulk:", promptError);
            // Continue with the template content as fallback
          }
        } else {
          console.log("No custom prompt provided for template", templateId);
        }

        // Create tags based on topic and template type
        const tags = [
          keyword,
          selectedTemplate?.category || "",
          selectedTemplate?.name || "",
          "Bulk Generated"
        ].filter(Boolean);

        // Create post with published status for Shopify sync
        const postResponse = await apiRequest({
          url: "/api/posts",
          method: "POST",
          data: {
            title,
            content,
            // Mark as published now, so it gets pushed to Shopify
            scheduledDate: null,
            publishedDate: new Date().toISOString(),
            status: "published", // Changed from "draft" to "published"
            tags: tags.join(","), // Tags is a text field in the schema, so join array to string
            category: selectedTemplate?.category || "General",
            storeId: null,
            author: "Bulk Generation"
          }
        });

        // If the post was created successfully, trigger Shopify sync
        if (postResponse && postResponse.post && postResponse.post.id) {
          try {
            // Trigger sync to Shopify
            await apiRequest({
              url: "/api/shopify/sync",
              method: "POST",
              data: {
                postIds: [postResponse.post.id]
              }
            });

            console.log(`Post "${title}" synced to Shopify successfully`);
          } catch (syncError) {
            console.error(`Error syncing post to Shopify:`, syncError);
            // Don't count as failed, as post was created successfully
          }
        }

        successCount++;

        // Update progress
        setGenerationResults(prev => ({
          ...prev,
          success: successCount,
          failed: failedCount
        }));
      } catch (error) {
        console.error(`Error generating article for keyword "${keyword}":`, error);
        failedCount++;

        // Update progress
        setGenerationResults(prev => ({
          ...prev,
          success: successCount,
          failed: failedCount
        }));
      }
    }

    // All done
    setGenerationResults(prev => ({
      ...prev,
      inProgress: false
    }));

    // Show result toast
    toast({
      title: "Bulk Generation Complete",
      description: `Generated ${successCount} of ${keywords.length} articles`,
    });

    // Invalidate posts query cache
    queryClient.invalidateQueries({ queryKey: ['/api/posts'] });

    // Navigate to blog posts page to see results
    setLocation("/blog-posts");
  };

  return (
    <Layout>
      <div className="md:flex md:items-center md:justify-between mb-6">
        <div className="flex-1 min-w-0">
          <h2 className="text-2xl font-semibold text-neutral-900">TopShop SEO Content Templates</h2>
          <p className="mt-1 text-sm text-neutral-500">
            Use pre-built templates to quickly create blog content
          </p>
        </div>
        <div className="mt-4 md:mt-0 md:ml-4 flex space-x-2">
          <Button variant="outline" onClick={handleOpenBulkGeneration}>
            <Zap className="mr-2 h-4 w-4" />
            Bulk Generate
          </Button>
          <Button onClick={handleCreateTemplate}>
            <Plus className="mr-2 h-4 w-4" />
            New Template
          </Button>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {templates.map((template) => (
          <TemplateCard 
            key={template.id} 
            template={template}
            onUse={handleUseTemplate}
            onEdit={handleEditTemplate}
          />
        ))}
      </div>

      {/* Single template usage dialog */}
      <TemplateUsageDialog
        isOpen={isDialogOpen}
        setIsOpen={setIsDialogOpen}
        template={selectedTemplate}
        onApply={handleApplyTemplate}
      />

      {/* Bulk generation dialog */}
      <BulkGenerationDialog
        isOpen={isBulkDialogOpen}
        setIsOpen={setIsBulkDialogOpen}
        onGenerate={handleBulkGeneration}
        templates={templates}
      />

      {/* Template editing dialog */}
      <TemplateEditDialog
        isOpen={isEditDialogOpen}
        setIsOpen={setIsEditDialogOpen}
        template={selectedTemplate}
        templateContent={selectedTemplate ? templateContent[selectedTemplate.id] : null}
        onSave={handleSaveTemplate}
      />

      {/* Template creation dialog */}
      <TemplateCreateDialog
        isOpen={isCreateDialogOpen}
        setIsOpen={setIsCreateDialogOpen}
        onSave={handleCreateNewTemplate}
      />

      {/* Progress indicator (conditionally shown) */}
      {generationResults.inProgress && (
        <div className="fixed bottom-4 right-4 bg-white shadow-lg rounded-lg p-4 w-80 border border-gray-200">
          <div className="flex items-center justify-between mb-2">
            <h3 className="font-medium">Generating Articles</h3>
            <Badge variant="outline" className="bg-blue-50 text-blue-700">
              {Math.round((generationResults.success + generationResults.failed) / generationResults.total * 100)}%
            </Badge>
          </div>
          <div className="space-y-2">
            <div className="w-full bg-gray-200 rounded-full h-2.5">
              <div
                className="bg-blue-600 h-2.5 rounded-full"
                style={{ width: `${((generationResults.success + generationResults.failed) / generationResults.total) * 100}%` }}
              ></div>
            </div>
            <div className="flex justify-between text-sm text-gray-500">
              <span>Success: {generationResults.success}</span>
              <span>Failed: {generationResults.failed}</span>
              <span>Total: {generationResults.total}</span>
            </div>
          </div>
        </div>
      )}
    </Layout>
  );
}

