import { useState } from "react";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { apiRequest } from "@/lib/queryClient";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Skeleton } from "@/components/ui/skeleton";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { useToast } from "@/hooks/use-toast";

import { Clock, Calendar, Edit, ExternalLink, AlertCircle } from "lucide-react";

interface ScheduledPost {
  id: number;
  title: string;
  content: string;
  status: string;
  contentType?: string; // Add contentType field from backend
  tags?: string; // Add tags field from backend
  author?: string;
  authorId?: number;
  scheduledDate?: string;
  scheduledPublishDate?: string;
  scheduledPublishTime?: string;
  storeId?: number;
  shopifyPostId?: string;
  createdAt: string;
  updatedAt: string;
  schedulingInfo?: {
    scheduledDate: string;
    scheduledDateLocal: string;
    timezone: string;
    isPastDue: boolean;
    minutesUntilPublish: number;
  };
  publishStatus?: {
    isScheduled: boolean;
    isPublished: boolean;
    hasShopifyId: boolean;
    shopifyUrl?: string;
  };
}

interface ScheduledPostsResponse {
  posts: ScheduledPost[];
  storeTimezone: string;
  store: {
    name: string;
    id: number;
  };
}

// Helper function to calculate minutes until publish
const calculateMinutesUntilPublish = (date: string, time: string, timezone: string): number => {
  try {
    const scheduled = new Date(`${date}T${time}:00`);
    const now = new Date();
    const diffMs = scheduled.getTime() - now.getTime();
    return Math.floor(diffMs / (1000 * 60));
  } catch {
    return 0;
  }
};

export function ScheduledPostsList() {
  const [editingPost, setEditingPost] = useState<ScheduledPost | null>(null);
  const [newDate, setNewDate] = useState("");
  const [newTime, setNewTime] = useState("");
  const { toast } = useToast();
  const queryClient = useQueryClient();

  const { data: scheduledData, isLoading, error } = useQuery<ScheduledPostsResponse>({
    queryKey: ["/api/posts/scheduled"],
    refetchInterval: 30000, // Refresh every 30 seconds to show live countdown
    staleTime: 10000, // Data becomes stale after 10 seconds
  });

  const updateScheduleMutation = useMutation({
    mutationFn: async ({ postId, scheduledPublishDate, scheduledPublishTime }: {
      postId: number;
      scheduledPublishDate: string;
      scheduledPublishTime: string;
    }) => {
      return await apiRequest({
        url: `/api/posts/${postId}`,
        method: "PUT",
        data: {
          scheduledPublishDate,
          scheduledPublishTime,
        },
      });
    },
    onMutate: async ({ postId, scheduledPublishDate, scheduledPublishTime }) => {
      // Cancel any outgoing refetches so they don't overwrite our optimistic update
      await queryClient.cancelQueries({ queryKey: ["/api/posts/scheduled"] });

      // Snapshot the previous value
      const previousData = queryClient.getQueryData(["/api/posts/scheduled"]);

      // Optimistically update the cache
      queryClient.setQueryData(["/api/posts/scheduled"], (old: ScheduledPostsResponse | undefined) => {
        if (!old) return old;

        return {
          ...old,
          posts: old.posts.map(post => 
            post.id === postId 
              ? { 
                  ...post, 
                  scheduledPublishDate, 
                  scheduledPublishTime 
                }
              : post
          )
        };
      });

      // Return a context object with the snapshotted value
      return { previousData };
    },
    onSuccess: (data) => {
      // Force immediate refetch of scheduled posts for accurate server calculations
      queryClient.invalidateQueries({ queryKey: ["/api/posts/scheduled"] });
      queryClient.refetchQueries({ queryKey: ["/api/posts/scheduled"] });
      // Also invalidate any related post queries
      queryClient.invalidateQueries({ queryKey: ["/api/posts"] });

      // Clear the form and close modal
      setEditingPost(null);
      setNewDate("");
      setNewTime("");

      const contentType = editingPost?.publishStatus?.hasShopifyId ? 
        (editingPost.tags?.includes('page') || editingPost.title?.includes('Page') ? 'Page' : 'Post') : 
        'Content';

      toast({
        title: `${contentType} Schedule Updated`,
        description: `Successfully updated to ${newDate} at ${newTime} (${scheduledData?.storeTimezone || 'EST'})`,
      });
    },
    onError: (error: any, variables, context) => {
      // Roll back the optimistic update if there was an error
      if (context?.previousData) {
        queryClient.setQueryData(["/api/posts/scheduled"], context.previousData);
      }

      // Extract a more user-friendly error message
      const errorMessage = error.message || "Failed to update post schedule.";
      const isTimeError = errorMessage.includes("Invalid schedule time") || errorMessage.includes("schedule time");

      toast({
        title: isTimeError ? "Invalid Schedule Time" : "Update Failed",
        description: isTimeError 
          ? `The scheduled time must be in the future. Current time in ${storeTimezone}: ${new Date().toLocaleString("en-US", { 
              timeZone: storeTimezone.includes('/') ? storeTimezone : 'America/New_York',
              hour: '2-digit',
              minute: '2-digit',
              hour12: true,
              month: 'short',
              day: '2-digit'
            })}`
          : errorMessage,
        variant: "destructive",
      });
    },
  });

  const formatTimeUntilPublish = (minutes: number) => {
    if (minutes <= 0) return "Past due";

    const days = Math.floor(minutes / (24 * 60));
    const hours = Math.floor((minutes % (24 * 60)) / 60);
    const mins = minutes % 60;

    if (days > 0) {
      return `${days}d ${hours}h ${mins}m`;
    } else if (hours > 0) {
      return `${hours}h ${mins}m`;
    } else {
      return `${mins}m`;
    }
  };

  const getStatusColor = (post: ScheduledPost) => {
    if (post.schedulingInfo?.isPastDue) return "destructive";
    if (post.publishStatus?.hasShopifyId) return "default";
    return "secondary";
  };

  const getStatusText = (post: ScheduledPost) => {
    const contentType = getContentType(post);
    if (post.schedulingInfo?.isPastDue) return `${contentType} Past Due`;
    if (post.publishStatus?.hasShopifyId) return `${contentType} Ready`;
    return `${contentType} Scheduled`;
  };

  const getContentType = (post: ScheduledPost): string => {
    // Priority 1: Use backend contentType field (most reliable)
    if (post.contentType === 'page') {
      return "Page";
    }
    if (post.contentType === 'post') {
      return "Post";
    }

    // Priority 2: Check tags for "page" indicator
    if (post.tags?.includes('page')) {
      return "Page";
    }

    // Priority 3: Check title for "page" keyword (least reliable)
    if (post.title?.toLowerCase().includes('page')) {
      return "Page";
    }

    // Default to Post
    return "Post";
  };

  const handleEditSchedule = (post: ScheduledPost) => {
    setEditingPost(post);
    setNewDate(post.scheduledPublishDate || "");
    setNewTime(post.scheduledPublishTime || "");
  };

  const handleUpdateSchedule = () => {
    if (!editingPost || !newDate || !newTime) {
      toast({
        title: "Invalid Input",
        description: "Please provide both date and time.",
        variant: "destructive",
      });
      return;
    }

    // Let the backend handle timezone validation since it has proper timezone logic
    // Frontend validation would be complex and error-prone with timezones
    // The backend will return a proper error message if the time is invalid

    updateScheduleMutation.mutate({
      postId: editingPost.id,
      scheduledPublishDate: newDate,
      scheduledPublishTime: newTime,
    });
  };

  if (isLoading) {
    return (
      <div className="space-y-4">
        <div className="flex items-center justify-between">
          <h3 className="text-lg font-semibold">Scheduled Posts</h3>
          <Skeleton className="h-4 w-32" />
        </div>
        {[...Array(3)].map((_, i) => (
          <Card key={i}>
            <CardHeader>
              <Skeleton className="h-4 w-3/4" />
              <Skeleton className="h-3 w-1/2" />
            </CardHeader>
            <CardContent>
              <Skeleton className="h-8 w-full" />
            </CardContent>
          </Card>
        ))}
      </div>
    );
  }

  if (error) {
    return (
      <Card>
        <CardContent className="pt-6">
          <div className="flex items-center gap-2 text-destructive">
            <AlertCircle className="h-4 w-4" />
            <span>Failed to load scheduled posts</span>
          </div>
        </CardContent>
      </Card>
    );
  }

  const { posts, storeTimezone, store } = scheduledData || { posts: [], storeTimezone: "UTC", store: { name: "", id: 0 } };

  if (posts.length === 0) {
    return (
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Calendar className="h-5 w-5" />
            Scheduled Posts
          </CardTitle>
          <CardDescription>
            No scheduled posts found for {store.name}
          </CardDescription>
        </CardHeader>
        <CardContent>
          <p className="text-sm text-muted-foreground">
            Posts scheduled for future publication will appear here. You can update their schedule times and monitor their status.
          </p>
        </CardContent>
      </Card>
    );
  }

  return (
    <div className="space-y-4">
      <div className="flex items-center justify-between">
        <h3 className="text-lg font-semibold flex items-center gap-2">
          <Calendar className="h-5 w-5" />
          Scheduled Posts ({posts.length})
        </h3>
        <Badge variant="outline" className="text-xs">
          {store.name} • {storeTimezone}
        </Badge>
      </div>

      <div className="grid gap-4">
        {posts.map((post) => (
          <Card key={post.id} className="relative">
            <CardHeader className="pb-3">
              <div className="flex items-start justify-between">
                <div className="space-y-1">
                  <CardTitle className="text-base line-clamp-2">
                    {post.title}
                  </CardTitle>
                  <CardDescription className="flex items-center gap-2 flex-wrap">
                    <Badge variant="secondary" className="text-xs">
                      {getContentType(post)}
                    </Badge>
                    {post.author && (
                      <span className="text-xs">by {post.author}</span>
                    )}
                    <Badge variant={getStatusColor(post)} className="text-xs">
                      {getStatusText(post)}
                    </Badge>
                  </CardDescription>
                </div>
                <div className="flex items-center gap-2">
                  <Dialog>
                    <DialogTrigger asChild>
                      <Button
                        variant="outline"
                        size="sm"
                        onClick={() => handleEditSchedule(post)}
                      >
                        <Edit className="h-3 w-3" />
                      </Button>
                    </DialogTrigger>
                    <DialogContent>
                      <DialogHeader>
                        <DialogTitle>Update Schedule</DialogTitle>
                      </DialogHeader>
                      <div className="space-y-4">
                        <div className="bg-blue-50 border border-blue-200 rounded-lg p-3 mb-4">
                          <div className="flex items-center gap-2 text-blue-800 text-sm font-medium">
                            <Clock className="h-4 w-4" />
                            Current Store Time
                          </div>
                          <div className="text-blue-700 text-lg font-mono mt-1">
                            {new Date().toLocaleString("en-US", {
                              timeZone: storeTimezone.includes('/') ? storeTimezone : 'America/New_York',
                              weekday: 'short',
                              month: 'short',
                              day: '2-digit',
                              hour: '2-digit',
                              minute: '2-digit',
                              hour12: true
                            })} ({storeTimezone})
                          </div>
                        </div>

                        <div>
                          <Label htmlFor="date">Publish Date</Label>
                          <Input
                            id="date"
                            type="date"
                            value={newDate}
                            onChange={(e) => setNewDate(e.target.value)}
                            min={new Date().toLocaleDateString("en-CA", {
                              timeZone: storeTimezone.includes('/') ? storeTimezone : 'America/New_York'
                            })}
                          />
                        </div>
                        <div>
                          <Label htmlFor="time">Publish Time ({storeTimezone})</Label>
                          <Input
                            id="time"
                            type="time"
                            value={newTime}
                            onChange={(e) => setNewTime(e.target.value)}
                          />
                          <p className="text-xs text-muted-foreground mt-1">
                            Select a time in the future according to your store's timezone
                          </p>
                        </div>
                        <Button
                          onClick={handleUpdateSchedule}
                          disabled={updateScheduleMutation.isPending}
                          className="w-full"
                        >
                          {updateScheduleMutation.isPending ? "Updating..." : "Update Schedule"}
                        </Button>
                      </div>
                    </DialogContent>
                  </Dialog>


                </div>
              </div>
            </CardHeader>

            <CardContent className="pt-0">
              <div className="flex items-center justify-between text-sm">
                <div className="flex items-center gap-4">
                  {/* Only show scheduled time if not past due and published */}
                  {!(post.schedulingInfo?.isPastDue && post.publishStatus?.isPublished) && (
                    <div className="flex items-center gap-1 text-muted-foreground">
                      <Clock className="h-3 w-3" />
                      <span>
                        {post.schedulingInfo?.scheduledDateLocal || 
                         `${post.scheduledPublishDate} ${post.scheduledPublishTime}`}
                      </span>
                    </div>
                  )}

                  {post.schedulingInfo && !post.publishStatus?.isPublished && (
                    <div className={`flex items-center gap-1 ${
                      post.schedulingInfo.isPastDue 
                        ? "text-destructive" 
                        : "text-primary"
                    }`}>
                      <span className="font-medium">
                        {formatTimeUntilPublish(post.schedulingInfo.minutesUntilPublish)}
                      </span>
                      {!post.schedulingInfo.isPastDue && <span>remaining</span>}
                    </div>
                  )}

                  {/* Show published status for published posts */}
                  {post.publishStatus?.isPublished && (
                    <div className="flex items-center gap-1 text-green-600">
                      <span className="font-medium">Published</span>
                    </div>
                  )}
                </div>

                <div className="flex items-center gap-2">
                  {post.publishStatus?.hasShopifyId && (
                    <Badge variant="outline" className="text-xs">
                      Synced to Shopify
                    </Badge>
                  )}

                  {post.schedulingInfo?.isPastDue && (
                    <Badge variant="destructive" className="text-xs">
                      <AlertCircle className="h-3 w-3 mr-1" />
                      Needs Attention
                    </Badge>
                  )}
                </div>
              </div>
            </CardContent>

            {post.schedulingInfo?.isPastDue && (
              <div className="absolute top-2 right-2">
                <div className="h-2 w-2 bg-destructive rounded-full animate-pulse" />
              </div>
            )}
          </Card>
        ))}
      </div>

      <div className="text-xs text-muted-foreground text-center">
        Times shown in {storeTimezone} • Updates every 30 seconds
      </div>
    </div>
  );
}
